var ayetHadisData = {"ayetler": [{"kisim": 1, "madde": 2, "metin": "Bunun pek kat’î ve kuvvetli olduğunu bildirmek için, âyet-i kerîmede (Elbette muhakkak böyledir) buyurdu ve ba’zı doğru düşünmiyenlerin, bu iki itâ’ati birbirinden ayrı görmelerine meydân bırakmadı."}, {"kisim": 1, "madde": 2, "metin": "Allahü teâlâ, yine Nisâ sûresinin yüzellinci ve yüzellibirinci âyet-i kerîmelerinde meâlen, (Kâfirler, Allahü teâlânın emrleri ile Peygamberlerinin emrlerini birbirinden ayırmak istiyorlar."}, {"kisim": 1, "madde": 2, "metin": "(Makâmât-i mazheriyye) onikinci faslında diyor ki, (Allahü teâlâya ve Resûlüne ve Onun Allahü teâlâdan getirdiklerinin hepsine inandım. Allahü teâlânın ve Resûlünün dostlarını severim ve düşmanlarını "}, {"kisim": 1, "madde": 4, "metin": "Allahü teâlânın Peygamberinin ve Onun Eshâbının “radıyallahü teâlâ anhüm ecma’în” yolunu kitâblara geçiren, değişdirilmekden ve bozulmakdan koruyan, (Ehl-i sünnet) âlimleridir. 5 — Dört mezhebde ictih"}, {"kisim": 1, "madde": 5, "metin": "İslâmiyyeti işitince, doğru olarak öğrenmek istiyene, Allahü teâlâ, bunu nasîb edeceğini va’d buyurmuşdur."}, {"kisim": 1, "madde": 8, "metin": "Çok ziyân etdi) olan onaltıncı âyet-i kerîmesi gönderildi."}, {"kisim": 1, "madde": 11, "metin": "[Hak teâlâ, Âl-i İmrân sûresinde kâfirlere kıymet verenlerin ve küfre tâbi’ olanların aldandıklarını ve pişmân olacaklarını beyân buyurarak meâli, (Ey benim sevgili Peygamberime “sallallahü aleyhi ve "}, {"kisim": 1, "madde": 11, "metin": "] Allahü teâlâ, kâfirlerin, kendi düşmanı ve Peygamberinin “sallallahü aleyhi ve sellem” düşmanı olduklarını bildiriyor. Allahü teâlânın düşmanlarını sevmek ve onlarla kaynaşmak, insanı Allahü teâlâya"}, {"kisim": 1, "madde": 12, "metin": "13 — Allahü teâlânın feyzleri, ni’metleri, ihsânları, ya’nî iyilikleri, her ân, insanların iyisine, kötüsüne, herkese gelmekdedir. Herkese mal, evlâd, rızk, hidâyet, irşâd ve selâmet ve dahâ her iyili"}, {"kisim": 1, "madde": 13, "metin": "Allahü teâlâ, bütün insanlara çok acıdığı için ve bir ananın yavrusuna olan merhametinden dahâ çok acıdığı için, dünyânın her tarafındaki, her insanın, her âilenin, her cem’ıyyetin ve milletin her zem"}, {"kisim": 1, "madde": 14, "metin": "14 — Allahü teâlânın rahmeti, şefkati dünyâda mü’minlere ve kâfirlere, herkese birlikde yetişdiği ve herkesin çalışmasına ve iyiliklerine dünyâda karşılığını verdiği hâlde, âhıretde kâfirlere merhamet"}, {"kisim": 1, "madde": 16, "metin": "Ya’nî Allahü teâlânın sevgilisidir. Her şeyin en iyisi, sevgiliye verilir. [Seyyid Abdülhakîm efendi buyurdu ki: (Her Peygamber, kendi zemânında, kendi mekânında, kendi kavminin hepsinden, her bakımda"}, {"kisim": 1, "madde": 16, "metin": "Allahü teâlânın, (Sen olmasaydın, gökleri yaratmazdım!) buyurduğu, (Ma’rifetnâme) önsözünde ve (Mevâhib-i ledünniyye)nin 6."}, {"kisim": 1, "madde": 18, "metin": "Tahrîm sûresinde altıncı âyet-i kerîmenin meâl-i şerîfi, (Kendinizi ve evlerinizde ve emrlerinizde olanları ateşden koruyunuz!)dur."}, {"kisim": 1, "madde": 18, "metin": "18 — Ona tâbi’ olmak (Ahkâm-ı islâmiyye)yi beğenip, seve seve yapmak ve Onun emrlerini ve islâmiyyetin kıymet verdiği, üstün tutduğu şeyleri ve âlimlerini, sâlihlerini büyük bilip, hurmet etmekdir ve "}, {"kisim": 1, "madde": 18, "metin": "Böyle gezenler, Allahü teâlâya âsî oldukları, günâha girdikleri gibi, bunların başında bulunan, baba, zevc, birâder ve amcadan hangisi, böyle gezmeğe rızâ verir ise, bu da, ısyân ve günâhda ortak olur"}, {"kisim": 1, "madde": 19, "metin": "Cenâb-ı Hakkın Îsâ aleyhisselâma emr-i ilâhîsinin meâl-i şerîfi, (Eğer yerlerde ve göklerde bulunan bütün mahlûkların ibâdetlerini yapsan, dostlarımı sevmedikce ve düşmanlarıma düşmanlık etmedikce, hi"}, {"kisim": 1, "madde": 19, "metin": "Her mü’min, Allahü teâlâya düşman olanları sevmemeli, islâmiyyete yapışanları sevmelidir. Bunu sözlerinde ve mümkin ise, hareketlerinde belli etmelidir. Âsî ve fâsıklarla arkadaşlık etmemeli, fıskı ço"}, {"kisim": 1, "madde": 21, "metin": "Nisâ sûresi, onüçüncü âyet-i kerîmesinde meâlen, (Allahü teâlânın ve Peygamberi Muhammed aleyhisselâmın emrlerine aldırış etmiyenler, beğenmiyenler, asra, fenne uygun değildir, modern ihtiyâclara kâfi"}, {"kisim": 1, "madde": 21, "metin": "Bu kısa zemânda, yalnız dünyâ lezzetleri ile zevklenmek için değil, belki bu fırsatda, tohum ekmek ve bir hayrlı iş, ya’nî Allahü teâlânın beğendiği işi yaparak, âyet-i kerîmede bildirilen katkat fazl"}, {"kisim": 1, "madde": 21, "metin": "Yoksa, Allahü teâlânın Peygamberine tâbi’ olmıyanların yapdığı her iyilik, dünyâda kalır ve âhıretin harâb olmasına sebeb olur. Ya’nî, iyilik şeklinde görünen, birer istidrâcdan başka birşey olamaz. 2"}, {"kisim": 1, "madde": 21, "metin": "Âl-i İmrân sûresi, seksenbeşinci âyetinde meâlen, (Muhammed aleyhisselâmın getirdiği İslâm dîninden başka din istiyenlerin, dinlerini Allahü teâlâ sevmez ve kabûl etmez. Dîn-i islâma arka çeviren, âhı"}, {"kisim": 1, "madde": 23, "metin": "[Nitekim, Nisâ sûresi yüzyetmişikinci âyet-i kerîmesinde meâlen, (Muhammed aleyhisselâma inanıp, âhırete yarayan işleri yapanlara [ya’nî ahkâm-ı islâmiyyeye uyanlara], Allahü teâlâ, va’d etdiklerini v"}, {"kisim": 1, "madde": 24, "metin": "Âhıret bilgileri ve Allahü teâlânın beğenip beğenmediği şeyler ve Ona ibâdet şeklleri, eğer aklın çerçevesi içinde olsalardı ve akl ile doğru olarak, bilinebilselerdi, binlerce Peygamberin gönderilmes"}, {"kisim": 1, "madde": 25, "metin": "Şöyle ki, bir arab şâ’iri, bir sahîfede, edebî san’at inceliklerini göstererek, birşey yazmış, bunun arasına birkaç satır hadîs-i şerîf ve başka yerinde de, aynı şeyi anlatan bir âyet-i kerîme koyup, "}, {"kisim": 1, "madde": 25, "metin": "Sıra, âyet-i kerîmeye gelince, şaşkın bir hâlde (Burası hiçbir söze benzemiyor."}, {"kisim": 1, "madde": 25, "metin": "Fekat, bu kelimeleri yanyana dizen, Allahü teâlâdır. Bu kelimeler, insan dizisi değildir. Muhammed “aleyhisselâm”, Allahü teâlâ tarafından, mubârek kalbine bildirilen şeyleri, arabca olarak anlatırsa,"}, {"kisim": 1, "madde": 26, "metin": "Ya’nî, her âyet-i kerîmede, ibâret, delâlet, işâret, iltizâm, iktizâ ve tazammün bakımından çeşidli ma’nâlar ve hükmler vardır."}, {"kisim": 1, "madde": 26, "metin": "(Nass), ma’nâları açık ve meydânda olan âyet-i kerîmelere ve hadîs-i şerîflere denir."}, {"kisim": 1, "madde": 26, "metin": "Hiçbir müctehid ve Eshâb-ı kirâmdan hiçbirisi “radıyallahü teâlâ anhüm ecma’în” başkalarının ictihâdlarına bozuk demedi. Kendilerine uymıyanlara, fâsık ve sapık gibi kötü şeyler söylemedi. Eshâb-ı kir"}, {"kisim": 1, "madde": 27, "metin": "O hâlde, ma’nâları açıkça anlaşılmayan âyet-i kerîme ve hadîs-i şerîflerin derinliklerinde bulunan ahkâm-ı islâmiyyeyi ve mesâil-i dîniyyeyi, mefhûm ile ve delâlet ile anlıyabilen büyüklere, ya’nî mut"}, {"kisim": 1, "madde": 31, "metin": "Diğer bütün günâhları, istediğim kimselerden afv ederim!) meâlindeki âyet-i kerîme meşhûrdur."}, {"kisim": 1, "madde": 31, "metin": "[Ya’nî, dünyâda, bütün insanlara fâideli şeyleri yaratıp göndermekle merhamet eden ve âhıretde, Cehennemi hak etmiş olan mü’minleri, afv ve inâyet buyuran, mahlûkâtı yaratan ve her ân varlıkda durdura"}, {"kisim": 1, "madde": 31, "metin": "Allahü teâlâya hamd ve şükrler olsun ki, şübhelerin artdığı şu zemânda, hiçbirşeye ihtiyâcı olmıyan sizin gibi bahtiyârlar, temiz mayalarının îcâbı olarak, hiçbir münâsebet olmadığı hâlde, bir köşede "}, {"kisim": 1, "madde": 32, "metin": "Hûd sûresindeki bir âyet-i kerîmeye verdiği ma’nâ gözüme ilişdi."}, {"kisim": 1, "madde": 35, "metin": "Bunlar, âyet-i kerîme gelmeden önce yapılmış olabilir denirse, zan etmekle cevâb verilmiş olmaz."}, {"kisim": 1, "madde": 35, "metin": "Âyet-i kerîmenin sonra geldiğini isbât etmek lâzımdır."}, {"kisim": 1, "madde": 35, "metin": "Bedenlerinin, a’zâlarının pis olmayabileceğini bildirmekdedir: Her hamd, Allahü teâlânın hakkıdır. Onun seçdiği temiz insanlara selâm ederim. Şefkatli efendim! Hüseyn Vâ’ızî tefsîrini niçin gönderdiği"}, {"kisim": 1, "madde": 35, "metin": "Ya’nî, Allahü teâlânın (Müşrikler pisdir) buyurması, kalblerinin, i’tikâdlarının pis olduğu içindir demişlerdir."}, {"kisim": 1, "madde": 36, "metin": "36 — BİR ÜNİVERSİTELİYE CEVÂB Abdülhakîm efendinin, İstanbulda, Sultân Selîm Câmi-i şerîfi bağçesindeki, (Medrese-tül-mütehassısîn)de tesavvuf müderrisi [Ya’nî, ilâhiyyât fakültesinde, tesavvuf kürsîs"}, {"kisim": 1, "madde": 36, "metin": "Şeyh buyurdu ki, (Öyle ise, şimdiden onlara cevâb hâzırla!) 6 — Kıyâmet günü Allahü teâlâ (Günâhı olanlar, Cehenneme gitsin!) diye emr edince, ben gitmem de! Soran kimse dedi ki, (Bu sözümü dinlemezle"}, {"kisim": 1, "madde": 38, "metin": "Dünyâda âhırete yarar iş görmek lâzım olduğu bildirilmekdedir: Allahü teâlâya hamd olsun! Allahü teâlâ bizi ve sizi, dedelerinizin doğru yolunda bulundursun! İnsanların en üstünü, sevgili Peygamberini"}, {"kisim": 1, "madde": 38, "metin": "Bu hadîs-i şerîfde, Peygamberimiz “sallallahü aleyhi ve sellem”, (Allahü teâlâ, yüzbin Âdem yaratmışdır) buyurmakdadır."}, {"kisim": 1, "madde": 39, "metin": "ci MEKTÛB Bu mektûb, Muhammed Takıyye cevâb olarak yazılmış olup, âlem-i misâl hakkında bilgi vermekde ve tenâsüh olmadığını bildirmekde ve insan rûhlarının nakl edilmediğini ve kümûn ve bürûz ne deme"}, {"kisim": 1, "madde": 40, "metin": "Bu âyet-i kerîmeden anlaşılıyor ki, insan ölürken rûhu ayrıldığı gibi, uyurken de ayrılmakdadır."}, {"kisim": 1, "madde": 41, "metin": "Allahü teâlâ için kâfirlerle cihâd etmek gibi sevâb verilir. Hele zâlim hükûmet adamları elinden mazlûmu kurtarmak ve memleketi kâfirlik kapladığı bir zemânda îmânı izhâr için olunca, böyle zemânlarda"}, {"kisim": 1, "madde": 41, "metin": "Allahü teâlâ için, ne gibi şeylere ve nasıl inanmak lâzım olduğu gibi. Bu kısmda olanları, âlimler emr ve nehy eder. Eğer bir âlim, bunları bildirdi ise, âlim olmayanın da, gücü yeterse, bildirmesi câ"}, {"kisim": 1, "madde": 42, "metin": "Allahü teâlâ lutf ederek, kerem ederek, acıyarak, kullarına çok şeyleri mubâh etmiş, izn vermişdir. Rûhu hasta, kalbi bozuk olduğu için, mubâhlarla doymayıp, bitmez tükenmez mubâhları bırakarak, ahkâm"}, {"kisim": 1, "madde": 43, "metin": "Nûr sûresi, otuzbirinci âyet-i kerîmesinde meâlen, (Ey mü’minler! Hepiniz, Allahü teâlâya tevbe ediniz! Tevbe etmekle kurtulabilirsiniz) buyurmuşdur."}, {"kisim": 1, "madde": 43, "metin": "Yirmisekizinci cüz’ sonundaki, Tahrîm sûresi, sekizinci âyet-i kerîmesinde meâlen, (Ey îmân eden seçilmişler! Allahü teâlâya dönünüz! Hâlis tevbe edin! Ya’nî tevbenizi bozmayın! Böyle tevbe edince, Ra"}, {"kisim": 1, "madde": 43, "metin": "Ya’nî bu mektûbu yazabilmek için, rahmeti, ihsânı bol olan Allahü teâlâya sığınıyor, Ona güveniyorum. Her hamd, şükr Onun hakkıdır. Onun seçdiği, sevdiği iyi insanlara selâm ederim. Kıymetli ömrümüz, "}, {"kisim": 1, "madde": 45, "metin": "ci MEKTÛB Esseyyid, Mîr Muhammed Nu’mân hazretlerine yazılmış olup, Allahü teâlânın ve sıfatlarının ve fi’llerinin kullarına çok yakın olduğunu bildirmekdedir: Allahü teâlâya hamd olsun ve Onun seçdiğ"}, {"kisim": 1, "madde": 46, "metin": "ci MEKTÛB Bu mektûb, dînine çok bağlı olan bir hanıma yazılmış olup, i’tikâdları bildirmekde, ibâdetlere teşvîk etmekdedir: Görünen, görünmiyen, bilinen, bilinmeyen bütün ni’metleri gönderen, bizlere "}, {"kisim": 1, "madde": 46, "metin": "O hâlde, her ni’metin hakîkî sâhibi olan Allahü teâlâya şükr etmek, insanlık îcâbıdır. Aklın lüzûm gösterdiği bir vazîfe, bir borcdur. Fekat, Allahü teâlâ, her ayb ve kusûrdan uzak, insanlar ise, ayb "}, {"kisim": 1, "madde": 47, "metin": "Allahü teâlâ, o büyük insanların çalışmalarına, bol bol mükâfât versin! [Dört mezhebin ictihâd derecesine yükselmiş müctehidlerine ve bunların yetişdirdikleri büyük âlimlere (Ehl-i sünnet) âlimi denir"}, {"kisim": 1, "madde": 48, "metin": "ci MEKTÛB Bu mektûb, Mirzâ Menû Cehre yazılmış olup, nasîhat vermekdedir: Allahü teâlâ, hayrlı ömürler ihsân buyursun! Se’âdet, iyilikler verip, başınızdan geçen acıları unutdursun! Yavrum! Gençlikde,"}, {"kisim": 1, "madde": 48, "metin": "[Hele başka mâni’ler de araya katılırsa, bunları dinlemeyip yapılan ibâdetin sevâbı o kadar çokdur ki, ancak Allahü teâlâ bilir.] Çünki, mâni’ler karşısında, ibâdeti yapmak güçlüğü, sıkıntısı, o ibâde"}, {"kisim": 1, "madde": 49, "metin": "(El-hâkka) sûresinde, bir âyet-i kerîmede meâlen, (Sûra bir kerre üfürülünce, yeryüzü ve dağlar, yerlerinden kaldırılıp silkilecekdir."}, {"kisim": 1, "madde": 49, "metin": "O gün kıyâmet kopacak, gök yarılacak ve dağılacakdır) ve (Tekvîr) sûresinde, bir âyet-i kerîmede meâlen, (Güneşin karardığı, yıldızların yerlerinden ayrılıp döküldükleri ve dağların dağılıp saçıldıkla"}, {"kisim": 1, "madde": 49, "metin": "Âlemin yokdan var edilmiş olduğunu bildirmekde ve Yunan felsefecilerinin akl-ı fe’âl dedikleri şeyi red etmekdedir: Âlemlerin rabbi olan Allahü teâlâya hamd olsun ve Peygamberlerin en üstününe salât v"}, {"kisim": 1, "madde": 49, "metin": "Allahü teâlâdan başka herşey yok idi ve hepsi yine yok olacaklardır. Kıyâmet kopacağı zemân, yıldızlar yerlerinden ayrılıp dağılacak, gökler parçalanacak, yeryüzü ve dağlar da parça parça olacak, heps"}, {"kisim": 1, "madde": 50, "metin": "Bir âyet-i kerîmede meâlen, (Ni’metlerime şükr ederseniz, onları artdırırım) buyurulmakdadır."}, {"kisim": 1, "madde": 50, "metin": "cü MEKTÛBU Allahü teâlânın emrlerine yapışmağı, nemâzın ehemmiyyetini bildirmekdedir: Bu bir köşede unutulmuşu hâtırlıyarak, kardeşim mevlânâ Muhammed Hanîf Kâbilî ile gönderdiğiniz mektûb geldi. Okuy"}, {"kisim": 1, "madde": 50, "metin": "Allahü teâlânın Peygamberi “sallallahü aleyhi ve sellem” buyurdu ki: (Bir mü’min nemâz kılmağa başlayınca, Cennet kapıları onun için açılır."}, {"kisim": 1, "madde": 54, "metin": "Allahü teâlâ, Meleklere, bu kuluma bakınız! Gece, üşenmeden kalkıp, benim emrimi düşünerek, cenâbetden gusl ediyor. Şâhid olunuz ki, bu kulumun günâhlarını afv ve magfiret eyledim buyurur)."}, {"kisim": 1, "madde": 62, "metin": "[(Sâvî) tefsîrinde, (İnşirâh) sûresinde diyor ki, (Allahü teâlâ, senin ismini şarkda, garbda, yer küresinin her yerinde yükseltirim buyurdu)."}, {"kisim": 1, "madde": 63, "metin": "Peygamberimiz “sallallahü teâlâ aleyhi ve sellem” el ile üçden fazla vurmağı bile, yasak etmişdi.] Çocuklara, başka ibâdetleri de öğretmek ve yapmağa alışdırmak, günâhlardan men’ etmek lâzımdır. Farz "}, {"kisim": 1, "madde": 63, "metin": "Buyurdu ki, (Nemâz kılmıyanlar, kıyâmet günü, Allahü teâlâyı kızgın olarak bulacaklardır). Hadîs imâmları, sözbirliği ile bildiriyor ki, (Bir nemâzı vaktinde amden kılmıyan, ya’nî nemâz vakti geçerken"}, {"kisim": 1, "madde": 73, "metin": "ci MEKTÛB Bu mektûb, mîr Muhammed Nu’mânın “kuddise sirruh” süâllerine cevâb olarak yazılmış olup, nemâzda otururken parmak kaldırmak doğru olmadığını da bildirmekdedir: Âlemlerin, bütün mahlûkların r"}, {"kisim": 1, "madde": 74, "metin": "İbni Teymiyye ve İbni Hazm, hükmü şübheli olan âyet-i kerîmeleri ve hadîs-i şerîfleri te’vîl etdiler."}, {"kisim": 1, "madde": 76, "metin": "ci MEKTÛB Bu mektûb, Efganistânlı Feth hâna yazılmış olup, ta’dîl-i erkânı, ahkâm-ı islâmiyyeye yapışmağı ve bid’atden kaçınmağı bildirmekdedir: Allahü teâlâya hamd olsun! Onun seçdiği, sevdiği iyi in"}, {"kisim": 1, "madde": 77, "metin": "cu MEKTÛB Bu mektûb, Muhammed Murâd-ı Bedahşîye yazılmış olup, nemâzın ta’dîl-i erkânı ve tumânîneti ve câmi’de safların düzeltilmesi ve kâfirlere karşı harbe giderken niyyetin düzeltilmesi ve teheccü"}, {"kisim": 1, "madde": 77, "metin": "Bir def’a da buyurdu ki, (Rükü’da ve secdelerde, belini yerine yerleşdirip biraz durmayan kimsenin nemâzını Allahü teâlâ kabûl etmez). Peygamberimiz “sallallahü aleyhi ve sellem”, bir kimseyi nemâz kı"}, {"kisim": 1, "madde": 79, "metin": "Allahü teâlâ, bu ayda, hergün oruc tutulmasını emr etdi. Bu ayda, geceleri terâvîh nemâzı kılmak da sünnetdir. Bu ayda, Allah için ufak bir iyilik yapmak, başka aylarda, farz yapmış gibidir. Bu ayda, "}, {"kisim": 1, "madde": 79, "metin": "Bu ayda, emri altında olanların [işçinin, me’mûrun, askerin ve talebenin] vazîfesini hafîfletenleri [patronları, âmirleri, kumandanları ve müdîrleri], Allahü teâlâ afv edip, Cehennem ateşinden kurtarı"}, {"kisim": 1, "madde": 82, "metin": "Tahtâvî “rahmetullahi teâlâ aleyh” (İmdâd) hâşiyesi, oruc sonunda diyor ki, (Nezr yapmanın câiz olduğu âyet-i kerîmeden ve hadîs-i şerîfden anlaşılmakdadır."}, {"kisim": 1, "madde": 82, "metin": "Hac sûresi, yirmidokuzuncu âyet-i kerîmesinde meâlen, (Adaklarını yerine getirsinler!) buyurulmuşdur."}, {"kisim": 1, "madde": 82, "metin": "Allahü teâlâya şükr olarak yapılmalıdır. Şükr secdesi yapmak gibidir.)] Nezri yerine getirmek lâzım olduğu, Kur’ân-ı kerîmde ve hadîs-i şerîfde bildirilmiş ve icmâ-i ümmet hâsıl olmuşdur. Hac sûresi, "}, {"kisim": 1, "madde": 85, "metin": "Allahü teâlâ, kullarına çok acıdığı için, ba’zı gecelere kıymet vermiş, bu gecelerdeki, düâ ve tevbeleri kabûl edeceğini bildirmişdir. Kullarının çok ibâdet yapması, düâ ve tevbe etmeleri için bu gece"}, {"kisim": 1, "madde": 85, "metin": "Addâs “radıyallahü teâlâ anh”, o zemân hıristiyan idi. Bunu işitince şaşırdı. (Yıllarca buralardayım. Kimseden böyle söz duymadım. Bu nasıl sözdür?) dedi. Resûlullah: Sen neredensin? buyurdu."}, {"kisim": 1, "madde": 92, "metin": "Allahü teâlânın bu emri, Âl-i imrân sûresinin, altmışbirinci âyet-i kerîmesinde bildirilmekdedir."}, {"kisim": 1, "madde": 92, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki: — Biliyor musunuz? Allahü teâlâ, hiç ölmez ve herşeyi varlıkda tutan Odur. Îsâ “aleyhisselâm” ise yok idi ve yok olacakdır. Onlar — Evet biliyoruz."}, {"kisim": 1, "madde": 92, "metin": "Bunun üzerine, Allahü teâlâ, onları mübâheleye çağırmasını emr etdi. Resûlullah “sallallahü aleyhi ve sellem” de, bana inanmıyorsanız, gelin sizinle mübâhele edelim. Ya’nî, (Hangimiz zâlim isek, yalan"}, {"kisim": 1, "madde": 93, "metin": "93 — ÎSÂ “aleyhisselâm” PEYGAMBERDİR, ONA\n TAPILMAZ Büyük islâm âlimi, (Tefsîr-i kebîr) ve çeşidli kıymetli kitâbların sâhibi, İmâm-ı Fahreddîn Râzî “rahmetullahi aleyh” Âl-i imrân sûresinde, altmışbi"}, {"kisim": 1, "madde": 94, "metin": "cu MEKTÛB İmâm-ı Rabbânî Müceddid-i elf-i sânî “kaddesallahü teâlâ esrârehül’azîz”, bu mektûbu molla Ârif Hutenî Bedahşîye yazmışdır. (Lâ ilâhe illallah) kelimesinin üstünlüklerini ve tenzîh makâmını "}, {"kisim": 1, "madde": 96, "metin": "96 — MUHAMMED ALEYHİSSELÂMIN AHLÂKI Aşağıdaki yazı, (Rıyâd-un-nâsıhîn) kitâbının üçüncü kısm, ikinci bâb, onuncu faslından terceme edilmişdir: Allahü teâlâ, sevgili Peygamberine verdiği iyilikleri, ih"}, {"kisim": 1, "madde": 96, "metin": "Akreme buyuruyor ki, Abdüllah ibni Abbâsdan işitdim: Bu âyet-i kerîmedeki (Huluk-ı azîm), ya’nî güzel huylar, Kur’ân-ı kerîmin bildirdiği ahlâkdır."}, {"kisim": 1, "madde": 96, "metin": "Huluk-ı azîm demek, Allahü teâlâ ile sır, gizli şeyleri bulunmak, insanlar ile de güzel huylu olmak demekdir. Çok kimselerin islâm dînine girmesine, Resûlullahın güzel ahlâkı sebeb oldu). Muhammed ale"}, {"kisim": 1, "madde": 97, "metin": "Bunu isbât eden âyet-i kerîme ve hadîs-i şerîflerden ba’zıları şunlardır: 1 — Kur’ân-ı kerîmden sonra en kıymetli, en doğru kitâb olan (Buhârî-yi şerîf)deki bir hadîs-i şerîfde, Peygamberimiz buyurdu "}, {"kisim": 1, "madde": 97, "metin": "Peygamberimizin “sallallahü teâlâ aleyhi ve sellem” ve bütün Peygamberlerin “aleyhimüsselâm” babalarının ve analarının hiçbiri kâfir değil, aşağı kimseler değildi. Bunu isbât eden âyet-i kerîme ve had"}, {"kisim": 1, "madde": 97, "metin": "2 — Binlerle hadîs kitâblarından ikinciliği kazanmış olan, imâm-ı Müslimin “rahmetullahi teâlâ aleyh” kitâbındaki hadîs-i şerîfde, (Allahü teâlâ, İsmâ’îl “aleyhisselâm” evlâdından, Kinâne ismindeki ki"}, {"kisim": 1, "madde": 98, "metin": "98 — SÜBHÂNE RABBİKE ÂYET-İ KERÎMESİ Kur’ân-ı kerîm okudukdan, düâ etdikden ve ders ve va’zlardan sonra (Sübhâne rabbike) âyet-i kerîmesini okumak, islâm memleketlerinde yapılagelen bir sünnetdir."}, {"kisim": 1, "madde": 98, "metin": "Ba’zı kimseler, bu âyet-i kerîmeyi değişdirerek, Sübhâne rabbinâ şeklinde okumak dahâ iyidir diyor."}, {"kisim": 1, "madde": 98, "metin": "3 — Hadîs ilmi mütehassısı meşhûr Taberânî diyor ki, Abdüllah ibni Abbâs “radıyallahü teâlâ anhümâ” buyurdu ki, (Resûlullah “sallallahü aleyhi ve sellem” nemâzda, selâm vermeden evvel, Sübhâne rabbike"}, {"kisim": 2, "madde": 1, "metin": "] Allahü teâlâya hamd, seçdiği iyi insanlara selâm ve düâ ederim. Kardeşim şeyh Hasenin mektûbunu okuyunca, çok sevindim. Kıymetli bilgiler ve ma’rifetler yazılı idi. Bunları anlayınca, pek hoşuma git"}, {"kisim": 2, "madde": 1, "metin": "ci sahîfede diyor ki, (Allahü teâlâya düâ ederken, Peygamberleri ve Sâlihleri vesîle etmek ve vesîle olmalarını onlardan istemek câizdir. Çünki mu’cize ve kerâmet, ölüm ile bitmez. Ölünce kerâmetin yo"}, {"kisim": 2, "madde": 2, "metin": "Ümmîdlendiğim ve kabûl olunacağını umduğum zemânlarda ve fakîrlerin toplantılarında, kahraman askerinize yardım, feth ve zafer ihsân etmesi için, Allahü teâlâya düâ etmekdeyim. Allahü teâlâ, abes, fâi"}, {"kisim": 2, "madde": 2, "metin": "Bunun içindir ki, Resûlullah “sallallahü aleyhi ve sellem”, gazâlarında ve sıkıntılı zemânlarında, muhâcirlerin fakîrleri hürmetine Allahü teâlâdan yardım dilerdi. Askeri, ordusu olduğu hâlde, muhâcir"}, {"kisim": 2, "madde": 3, "metin": "Allahü teâlâya sığınınız ve Ona yalvarınız ki, bu iki büyük ni’metde gevşeklik olmasın. Bu ikisi olunca, başka şeylerin düzelmesi kolaydır. Size dahâ önce de yazmışdım ki, Mankpûrda bulunmakdan sıkılı"}, {"kisim": 2, "madde": 5, "metin": "Kelâm ilminin, âyet-i kerîmelerden ve hadîs-i şerîflerden nasıl çıkarıldığını öğreten ilmdir."}, {"kisim": 2, "madde": 5, "metin": "Fıkh bilgilerinin âyet-i kerîmelerden ve hadîs-i şerîflerden nasıl çıkarıldığını öğretir."}, {"kisim": 2, "madde": 6, "metin": "13 — (Hadîs-i kavî): Söyledikden sonra, bir âyet-i kerîme okuduğu hadîsdir."}, {"kisim": 2, "madde": 6, "metin": "6 — HADÎS-İ ŞERÎFLERİN ÇEŞİDLERİ [1308] senesinde İstanbulda basılan, (Mahzen-ül’ulûm) kitâbının, birinci cüz’, yüzotuzaltıncı sahîfesinde ve (Eşi’at-ül-leme’ât)in üçüncü sahîfesinde hadîs-i şerîfleri"}, {"kisim": 2, "madde": 6, "metin": "2 — (Hadîs-i müsned): Resûl-i ekreme “sallallahü aleyhi ve sellem” isnâd eden Sahâbînin “radıyallahü teâlâ anhüm ecma’în” ismi bildirilen hadîs-i şerîflerdir. Müsned hadîsler, müttasıl veyâ münkatı’ o"}, {"kisim": 2, "madde": 7, "metin": "Allahü teâlânın bildirdiği tiryâk ile bu zehrlere ilâc yapmıyanlara yazıklar olsun! Bu şekerli, tatlı zehrleri, islâmiyyetin emrlerini ve yasaklarını yapmak güçlüğüne katlanarak tedâvî etmiyenlere çok"}, {"kisim": 2, "madde": 8, "metin": "İnsanın hergün başına gelen şeylerin hepsinin, Allahü teâlânın irâdesi ile geldiği ve bunun için hepsinden lezzet duyulması lâzım olduğu bildirilmekdedir: Hak teâlâ, Muhammed aleyhisselâmın dîni yolun"}, {"kisim": 2, "madde": 9, "metin": "Allahü teâlâ, sevgili Peygamberine “aleyhi ve alâ âlihissalâtü vesselâm” emr olarak, Ahkâf sûresinde, (Peygamberlerden Ulül’azm olanların sabr etdikleri gibi Sen de sabr et! Onlara azâb verilmesi için"}, {"kisim": 2, "madde": 11, "metin": "Kalbini toparlıyamadığını bildiren mektûbuna cevâb vermekde, korkulu zemânda okunacak şeyleri bildirmekdedir: Allahü teâlâya hamd ve Onun sevgili Peygamberine salât eder, size de düâlar ederim. Azâ, y"}, {"kisim": 2, "madde": 13, "metin": "Allahü teâlâya kul olmak ni’metine kavuşmak, ancak (Vilâyet-i hâssa) hâsıl olunca ele geçer. Böyle velî olmak da, tam (Fenâ) ve olgun (Bekâ)dan sonra nasîb olur. Süâl: Böyle olan Evliyânın da dilekler"}, {"kisim": 2, "madde": 13, "metin": "Az bir zemân sonra, Allahü teâlânın yardımı ile kendimi toparladım. O düşüncelerin, bulutların açılması gibi, dağılıp gitdiklerini gördüm. Bunları gönlüme getiren de, onlarla birlikde uzaklaşdı. Kalbi"}, {"kisim": 2, "madde": 14, "metin": "Kibr ve ucbun hastalık olduğu bildirilmekdedir: Allahü teâlâya hamd olsun ve Onun seçdiği kullarına selâm olsun! Soruyorsunuz ki, riyâzet yapınca, ibâdet yapınca, nefsim kabarıyor. Benim gibi sâlih, i"}, {"kisim": 2, "madde": 14, "metin": "Bu felâketden yalnız Allahü teâlânın diledikleri kurtulabilir. İbâdetlerini, iyiliklerini kusûrlu, bozuk görmeğe kavuşan bir kimse, öyle bir hâle gelir ki, sağ omuzundaki, iyilikleri yazan meleğin hiç"}, {"kisim": 2, "madde": 15, "metin": "Allah diye yalvarınız!) meâlinde müteaddid âyet-i kerîmeler vardır."}, {"kisim": 2, "madde": 15, "metin": "15 — ALLAHÜ TEÂLÂNIN İSMLERİ Allahü teâlânın ismleri çokdur. Sayısını bilmiyoruz. İsmlerinden doksandokuzunu, Kur’ân-ı kerîmde insanlara bildirmişdir. Kâdî zâde Ahmed efendi, (Birgivî vasıyyetnâmesi) "}, {"kisim": 2, "madde": 15, "metin": "Taş veyâ kurd, köpek veyâhud en aşağı, büyük düşmanının ismi ile çağırmak istiyoruz) deseler ve öyle çağırsalar, nasıl çok kızarsa, Allah ismi yerine, Onun emr etmediği, hattâ düşmanı olduğu tanrı ism"}, {"kisim": 2, "madde": 16, "metin": "Eshâb-ı kirâma “radıyallahü teâlâ anhüm ecma’în” ve bunlardan sonraki asrda gelen müctehidlere (Selef-i sâlihîn) denildiğini, ikinci kısmın dördüncü maddesinde, îmânı anlatırken bildirmişdim. Selef-i "}, {"kisim": 2, "madde": 17, "metin": "Puta tapanlar için gelmiş olan âyet-i kerîmelerle, bu sözlerini isbâta kalkışıyorlar."}, {"kisim": 2, "madde": 18, "metin": "18 — ŞEFÂ’AT, ÖLÜLERE YARDIM Süâl: Zümer sûresinin, otuzuncu âyetiyle sarâhaten, Peygamberimizin “sallallahü aleyhi ve sellem” öldüğü belli iken, hâlâ kabr ziyâreti ile ölülerden şefâ’at istemek olur "}, {"kisim": 2, "madde": 18, "metin": "Kur’ân-ı kerîmin ma’nâsını anlıyabilmek için, ilm-i lügat, ilm-i metn-i lügat, ilm-i bedî’, ilm-i beyân, ilm-i me’ânî, ilm-i belâgat, ilm-i üsûl-i tefsîr gibi çeşidli ilmleri iyi öğrenmek, sarf, nahv,"}, {"kisim": 2, "madde": 19, "metin": "Fudûl işlerden vazgeçip, zarûrî lâzım olanları yapmak lâzım olduğu bildirilmekdedir: Allahü teâlâya hamd olsun ve Onun seçdiği, sevdiği kullarına selâm olsun! Kıymetli mektûbunuzu okumakla şereflendim"}, {"kisim": 2, "madde": 20, "metin": "Kabr azâbına inanmıyanların şübhelerini gidermek için yazılmışdır: Allahü teâlâya hamd olsun! Onun seçdiği, sevdiği kullarına selâm olsun! Kabrde azâb yapılacağı sahîh ve meşhûr hadîsler ile, hattâ Ku"}, {"kisim": 2, "madde": 20, "metin": "Böylece, insanların Allahü teâlâya özr, behâne yapmaları önlendi) buyuruldu."}, {"kisim": 2, "madde": 23, "metin": "Bu âyet-i kerîmenin, Ömer “radıyallahü anh” müslimân olduğu için indiğini, Abdüllah ibni Abbâs “radıyallahü anhümâ” bildiriyor."}, {"kisim": 2, "madde": 23, "metin": "Vennecmi sûresindeki, (O, boş söz söylemez!) meâlindeki âyet-i kerîme, Kur’ân-ı kerîm içindir."}, {"kisim": 2, "madde": 23, "metin": "cı MEKTÛB Bu mektûb, hâce Ebül-Hasen Behâdır Bedahşîye yazılmış olup, Peygamberimizin “sallallahü aleyhi ve sellem” vefât edeceğine yakın kâğıd istediğini açıklamakdadır: Allahü teâlâya hamd olsun. On"}, {"kisim": 2, "madde": 23, "metin": "Ömer “radıyallahü anh” birkaç Sahâbî ile birlikde, (Bize Allahü teâlânın kitâbı yetişir! Soralım, sayıklıyor mu?) dedi. Hâlbuki, Resûlullahın “sallallahü aleyhi ve sellem” her sözü vahy ile idi. Nitek"}, {"kisim": 2, "madde": 24, "metin": "Kayyûm-i rabbânî, Muhammed Ma’sûm-i Fârûkî Serhendî “rahmetullahi aleyh” (Mektûbât)ının ikinci cildi, otuzaltıncı mektûbunda, sekizinci süâlin cevâbında buyuruyor ki: Tepeden tırnağa kadar rahmet olan"}, {"kisim": 2, "madde": 24, "metin": "Bir başka hadîs-i şerîfde, (Şeytâna söğmeyiniz! Şerrinden, Allahü teâlâya sığınınız) buyuruldu."}, {"kisim": 2, "madde": 25, "metin": "Bu âyet-i kerîme, onun için indirilmişdir."}, {"kisim": 2, "madde": 25, "metin": "Allahü teâlâ, hepsine Cenneti va’d etdi) buyuruldu."}, {"kisim": 2, "madde": 28, "metin": "Allahü teâlânın merhameti sonsuz olduğundan, insanlarda, se’âdeti felâketden, doğruyu iğriden ve fâideliyi zararlıdan ayırabilen bir kuvvet de yaratdı. Bu çok kıymetli kuvvet, (Akl)dır. Şaşmıyan, yanı"}, {"kisim": 2, "madde": 28, "metin": "Akllarına uymayıp, nefslerine uyarak, Allahü teâlânın da’vetini kabûl etmiyenlerden, dilediklerini kendi taşkın, azgın hâllerinde bırakmakda, dilediklerini de, yine ihsân ederek, dilediği zemânda hidâ"}, {"kisim": 2, "madde": 30, "metin": "Kâdî Beydâvî “rahmetullahi aleyh”, Nahl sûresinde, (Kullarıma hikmet ile ve güzel va’z ile beni tanıt!) meâlindeki yüzyirmibeşinci âyet-i kerîmeyi tefsîr ederken, (Anlayışlı, tahsîlli olanlara, fen bi"}, {"kisim": 2, "madde": 30, "metin": "Neml sûresindeki, meâl-i şerîfi, (Dağları, yerinde duruyor görüyorsun, hâlbuki bunlar bulut gibi hareket etmekdedir) olan seksensekizinci âyet-i kerîmesini Kâdî Beydâvî tefsîr ederken, (Yerinde duruyo"}, {"kisim": 2, "madde": 30, "metin": "Bunu okutmasını hoş görmiyen biri, müslimân çocuklarına böyle ne okutuyorsun diye sorunca, meâl-i şerîfi, (Yerleri, gökleri, yıldızları, bitkileri ne güzel yaratdığımızı görmiyorlar mı?) olan Kaf sûre"}, {"kisim": 2, "madde": 30, "metin": "İnsanların çoğu, gördüklerine, duyduklarına, göründüğü gibi inanıp, içlerini, inceliklerini anlıyamadıklarından, Allahü teâlâ, kitâblarında, varlığına, büyüklüğüne alâmet olan, mahlûklarının en büyükl"}, {"kisim": 2, "madde": 30, "metin": "Yehûdî ve hıristiyanlar, kitâblarında, görünüşe göre bildirilenleri okuyunca, hakîkatleri de böyle sanarak, yeryüzünü düz ve hareketsiz, güneşin bunun etrâfında döndüğünü, göklerin yer üzerine çadır g"}, {"kisim": 2, "madde": 34, "metin": "Eshâb-ı kirâmın ve Tâbi’înin “radıyallahü teâlâ anhüm ecma’în” zemânları ve hâlleri, evlenmenin dahâ iyi olduğunu gösteriyordu. Bunda, üç sebeb vardı: 1. ci sebeb: Muhammed Mustafâ “sallallahü aleyhi "}, {"kisim": 2, "madde": 34, "metin": "Allahü teâlânın yolunda, yalnız ruhbânlıkla gidilebilir düşüncesini gönüllerden çıkardı. Eshâb-ı kirâmın ve Tâbi’înin ve Tebe-i tâbi’înin “radıyallahü teâlâ anhüm ecma’în” zemânı olan ikiyüz sene için"}, {"kisim": 2, "madde": 35, "metin": "(Allahü teâlânın harâm etdiği şeye ehemmiyyet vermiyen kimse, islâm şerefini gayb etmişdir. İslâmiyyet, şerefli kadınları örterek kıymetlendirir) buyurdu."}, {"kisim": 2, "madde": 39, "metin": "Sûre-i nisâ otuzbirinci âyet-i kerîmede, kadınların kesb edeceği kazanclarından nasîb alacaklarını, Allahü teâlâ bildirmekdedir."}, {"kisim": 2, "madde": 39, "metin": "(Tenbîh-ul-gâfilîn)de ve (Şir’a) şerhinde yazılı hadîs-i şerîfde, Peygamberimiz “sallallahü teâlâ aleyhi ve sellem”, (Bir kadın, beş vakt nemâzını kılar, Ramezân ayında oruc tutar, nâmûsunu korur ve z"}, {"kisim": 2, "madde": 40, "metin": "Ve buyurdu ki, (Bir kimse, hiç harâm karışdırmadan, kırk gün halâl yirse, Allahü teâlâ, onun kalbini nûr ile doldurur. Kalbine, nehrler gibi hikmet akıtır. Dünyâ muhabbetini, kalbinden giderir). [Düny"}, {"kisim": 2, "madde": 40, "metin": "Yine buyurdu ki, (Malın halâlden mi, harâmdan mı geldiğini düşünmiyenler, Cehenneme, neresinden atılırsa atılsınlar, Allahü teâlâ, onlara acımıyacakdır). Yine buyurdu ki, (İbâdet on kısmdır, dokuz kıs"}, {"kisim": 2, "madde": 41, "metin": "Libya hükûmeti Evkaf idâresinin çıkardığı (El-Hedyül-islâmî) adındaki Mecellenin 1393 Hicrî ve 1973 Mîlâdî senesi ikinci sayısında, Libya Müftîsi şeyh Tâhir-üz-Zâvî, fetvâsında diyor ki, (Hadîs-i şerî"}, {"kisim": 2, "madde": 43, "metin": "Hanefî mezhebine gelince; büyük âlim İbni Nüceym-i Mısrî “rahmetullahi teâlâ aleyh”, (Eşbâh) kitâbında buyuruyor ki, (Âyet-i kerîmede ve hadîs-i şerîflerde harâm olduğu bildirilmiyen şeyler, aslı üzer"}, {"kisim": 2, "madde": 43, "metin": "Âyet-i kerîme ile yasak edilmesini bekledi."}, {"kisim": 2, "madde": 44, "metin": "İsrâ sûresindeki âyet-i kerîmede de meâlen, (Tebzîr etme! Tebzîr edenler, şeytânların kardeşleridir) buyuruyor."}, {"kisim": 2, "madde": 44, "metin": "Nisâ sûresindeki âyet-i kerîmede meâlen, (Mallarınızı sefîhlere, alçaklara vermeyiniz!) buyuruyor."}, {"kisim": 2, "madde": 44, "metin": "İsrâfın kötülüğünü göstermek için, Allahü teâlânın, (İsrâf etmeyiniz! Allahü teâlâ, isrâf edenleri sevmez) meâlindeki kelâmı yetişir. İsrâ sûresindeki âyet-i kerîmede de meâlen, (Tebzîr etme! Tebzîr e"}, {"kisim": 2, "madde": 44, "metin": "Allahü teâlâ, mallarını isrâf edenlere birşey vermeyiniz diye emr ederken, bunları en kötü bir ism ile adlandırıyor. Nisâ sûresindeki âyet-i kerîmede meâlen, (Mallarınızı sefîhlere, alçaklara vermeyin"}, {"kisim": 2, "madde": 45, "metin": "Bir hadîs-i şerîfde, (Çok yiyeni, çok içeni Allahü teâlâ sevmez) buyurdu."}, {"kisim": 2, "madde": 46, "metin": "(Su zarar verince, kullanmayın, teyemmüm edin!) meâlindeki âyet-i kerîme meşhûrdur."}, {"kisim": 2, "madde": 46, "metin": "46 — HASTA YEMEKLERİ Allahü teâlânın âdeti şöyledir ki, herşeyi sebeble yaratır. Birşeye kavuşmak için, bu şeyin yaratılmasına sebeb olan şeyi yapmak lâzımdır. Herşeyin yaratılmasında müşterek olan ma"}, {"kisim": 2, "madde": 47, "metin": "(Tevekkül îmânın şartıdır) meâlindeki âyet-i kerîme, bu emrlerden biridir."}, {"kisim": 2, "madde": 47, "metin": "cü âyet-i kerîmede, (Eğer îmânınız varsa, Allahü teâlâya tevekkül ediniz!), sûre-i Âl-i İmrânda, 159."}, {"kisim": 2, "madde": 47, "metin": "Çünki bir kimse, hareketlerde, işlerde, Allahü teâlâdan başkasının te’sîr etdiğini düşünse, bu kimsenin tevhîdi, noksân olur. Eğer, hiçbir sebeb lâzım değildir dese, islâmiyyetden ayrılmış olur. Eğer "}, {"kisim": 2, "madde": 47, "metin": "İşlerine sihr, büyü, dağlamak, fal karışdırmayıp, Allahü teâlâdan başkasına, tevekkül ve i’timâd etmiyenlerdir buyuruldu)."}, {"kisim": 2, "madde": 48, "metin": "Ümm-ül-kitâb, Ondadır) meâlindeki âyet-i kerîmede, levh-i mahfûz bildirilmekdedir."}, {"kisim": 2, "madde": 48, "metin": "Üçünü de sâdeleşdirerek, yazmayı uygun gördük: Ra’d sûresindeki, (Allahü teâlâ, dilediğini siler. Dilediğini değişdirmez. Ümm-ül-kitâb, Ondadır) meâlindeki âyet-i kerîmede, levh-i mahfûz bildirilmekde"}, {"kisim": 2, "madde": 48, "metin": "Allahü teâlânın kazâsından kaçıyor musun? dediklerinde, Allahü teâlânın kazâsından, kaderine kaçıyorum buyurdu ki, kader, kazâ şeklini almadıkca değişebilir."}, {"kisim": 2, "madde": 49, "metin": "49 — İRÂDE-İ CÜZ’İYYE İrâde-i cüz’iyye risâlesini Muhammed Akkermânî “rahmetullahi aleyh” yazmışdır: Dehr [veyâ İnsan] sûresindeki, (Siz, ancak Allahü teâlânın dilediğini arzû edersiniz!) meâlindeki â"}, {"kisim": 2, "madde": 49, "metin": "Yukarıdaki âyet-i kerîmenin ma’nâsını, Ebû Mensûr-i Mâtürîdî “rahmetullahi teâlâ aleyh” şöyle açıklıyor: (İhtiyârî işleriniz, yalnız sizin irâdenizle olmaz."}, {"kisim": 2, "madde": 50, "metin": "Sonra, onu Cehennemde (Sa’ûd) adındaki ateşden tepelere koyacağım), (Ebû Lehebin elleri kurusun! Sonra kurudu) meâlindeki âyet-i kerîmede Allahü teâlâ, bir kimsenin îmân etmiyeceğini haber veriyor."}, {"kisim": 2, "madde": 50, "metin": "Nitekim, Fahreddîn-i Râzî, Bekara sûresinin baş tarafındaki, (Allahü teâlâ, onların kalblerini mühürlemişdir!) meâlindeki âyet-i kerîmeden de, cebr lâzım gelir."}, {"kisim": 2, "madde": 50, "metin": "Cevâb şöyle verilir: Yapılacak günâhları, Allahü teâlâ, ezelde biliyordu. Fekat, insanın iyiliği, kötülüğü, Cennetlik, Cehennemlik olacağı, son nefesde belli olur. Peygamberimiz “sallallahü aleyhi ve "}, {"kisim": 2, "madde": 53, "metin": "Şeyh-i ekber [Muhyiddîn-i Arabî] “kuddise sirruh”, Cinnin var olduğunu, şu âyet-i kerîmeler ile gösteriyor: 1 — Zâriyât sûresinin ellialtıncı âyetinde meâlen, (İnsanları ve Cinnîleri ancak, beni bilip"}, {"kisim": 2, "madde": 53, "metin": "Cinnîleri anlatan âyet-i kerîmelere, akllarına göre, başka ma’nâ verenler mürted olur."}, {"kisim": 2, "madde": 53, "metin": "Çünki, Allahü teâlânın kudretinin yapamıyacağı birşey değildir. Bugün fen adamları, akl ve din sâhibleri, aklın imkânsız demediği şeyleri red etmiyor. Kur’ân-ı kerîmde bildirilen şeylere, kelimenin aç"}, {"kisim": 2, "madde": 54, "metin": "Fekat, bunlar diyor ki, Allahü teâlâ, benim üstâdımın rûhuna öyle bir kuvvet vermişdir ki, her nerede ve ne zemânda çağırır isem, imdâdıma hâzır olur. Görülüyor ki, Fahr-i âlem “sallallahü aleyhi ve s"}, {"kisim": 2, "madde": 57, "metin": "İkra’ sûresindeki âyet-i kerîmede meâlen, (İnsan, ihtiyâcsız olunca, elbette azar!) buyuruldu."}, {"kisim": 2, "madde": 57, "metin": "Buna benzer şeyleri de bildirmekdedir: Allahü teâlâya hamd olsun ve Onun seçdiği, sevdiği kullarına selâm olsun! Görünen ve görünmiyen iyiliklere kavuşmanızı Allahü teâlâdan düâ ederim. Çünki, sizin i"}, {"kisim": 2, "madde": 58, "metin": "Allahü teâlâ, karşılık olarak, en iyi şeyler ihsân buyursun! Sıhhat haberinizi duymakla çok sevindik."}, {"kisim": 2, "madde": 61, "metin": "Sûre-i Mücâdele, onsekizinci [18] âyet-i kerîmesinin: (Onlar iyi bir iş yapdıklarını sanıyor."}, {"kisim": 2, "madde": 61, "metin": "ci MEKTÛB Bu mektûb, Seyyid mîr Muhammed Nu’mâna “kuddise sirruh” yazılmış olup, Evliyâlık, Allahü teâlâya yakınlık demekdir. Velî olmak için hârikalar ve kerâmetler şart olmadığı bildirilmekdedir: Al"}, {"kisim": 2, "madde": 61, "metin": "Bilmiyorlar ki, Allahü teâlâ, o büyükleri, câhillerin gözünden saklamış, kendine mahsûs kılmışdır. Evliyâsını dünyâ işleri ile meşgûl etmeyip, kendisi ile meşgûl etmişdir. Evliyâ, insanların hâllerine"}, {"kisim": 2, "madde": 62, "metin": "Mü’minûn sûresinin ellidördüncü âyetinde ve Rum sûresindeki bir âyet-i kerîmede meâlen, (Her fırkada bulunanlar, kendi anladıklarını doğru sanırlar) buyuruluyor."}, {"kisim": 2, "madde": 62, "metin": "Seçilmişler, Allahü teâlânın cemâl ve celâl perdeleri ve tecellîler, zuhûrlar vâsıtası ile gaybın varlığını anlıyarak inanmışlardır. Bu iki kısmın arasında bulunan tesavvufcular ise, perdeleri ve tece"}, {"kisim": 2, "madde": 63, "metin": "[Ehl-i sünnet âlimleri, açık bildirilmemiş olan, ya’nî, ma’nâları şübheli olan âyet-i kerîmeleri (Te’vîl) etmişlerdir."}, {"kisim": 2, "madde": 71, "metin": "ci MEKTÛB Büyük âlim Abdüllah-i Dehlevînin “kaddesallahü teâlâ sirrehül’azîz” (Mekâtib-i şerîfe) kitâbındaki altmışbirinci mektûb, hâce Hasen Mevdûda yazılmış olup, aşağıdadır: Üstünlüğünü gösteren ke"}, {"kisim": 2, "madde": 72, "metin": "ci MEKTÛB Büyük âlim Abdüllah-i Dehlevînin “rahmetullahi teâlâ aleyh” (Mekâtib-i şerîfe) kitâbının seksenbeşinci mektûbu aşağıdadır: Allahü teâlâya hamd olsun! Onun sevgili Peygamberi Muhammed aleyhis"}, {"kisim": 2, "madde": 73, "metin": "[Bir kelimenin, Allahü teâlâ ve Resûlullah tarafından, açık bildirilmemiş ma’nâlarından, islâmiyyete uygun olanı seçmeğe (Te’vîl) denir. Bunu herkes yapamaz.] Evliyânın sözlerini de te’vîl etmek, meâl"}, {"kisim": 2, "madde": 73, "metin": "Böyle sözlerini işitince, (doğrusunu Allahü teâlâ bilir) demeli, inkâra kalkışmamalıdır). Tesavvuf yolundan maksad, Ehl-i sünnet âlimlerinin bildirdikleri doğru i’tikâda ve islâmın güzel ahlâkına ve f"}, {"kisim": 3, "madde": 1, "metin": "cü MEKTÛB Bu mektûb, üstâdı Muhammed Bâkî Billahın “kuddise sirruh” oğlu Hâce Muhammed Abdüllaha “sellemehullahü ve ebkâhu ve evsalehu ilâ gâyeti mâ yetemennâhu” yazılmış olup, işin başı, sünnet-i sen"}, {"kisim": 3, "madde": 1, "metin": "Allahü teâlâyı unutacaklar. Yalnız paraya tapınacaklar. Kadınlara köle olacaklar. Az kazanmak ile kanâ’at etmiyecekler. Çok kazanınca doymıyacaklar). Abdülvehhâb-ı Şa’rânî “rahmetullahi aleyh”, (Tezki"}, {"kisim": 3, "madde": 2, "metin": "ci MEKTÛB Bu mektûb, bir sâliha hanıma “rahmetullahi teâlâ aleyhâ” yazılmış olup, kadınlara lâzım olan nasîhatleri bildirmekdedir: Kadınların, Resûlullaha “sallallahü aleyhi ve sellem” söz verdiklerin"}, {"kisim": 3, "madde": 2, "metin": "Sûre-i Yûsüfdeki âyet-i kerîmede meâlen, (Biz, Allahü teâlânın varlığına, birliğine, herşeyi yaratan O olduğuna inandık, müslimân olduk diyenlerin çoğu, başkalarına ibâdet ve itâ’at ederek ve dahâ bir"}, {"kisim": 3, "madde": 2, "metin": "Allahü teâlânın emrlerini yapmış olmak için, bunlardan kaçınmak lâzım geldiği bildirildi. Birinci şart: Allahü teâlâdan başka, hiçbirşeye ibâdet etmemekdir. Bir kimse, başkaları görmek için ibâdet ede"}, {"kisim": 3, "madde": 3, "metin": "Buyurdu ki, (Allahü teâlâ güzeldir. Yalnız güzel yapılan ibâdetleri kabûl eder. Allahü teâlâ, Peygamberlerine emr etdiğini, mü’minlere de emr etdi ve buyurdu ki, ey Peygamberlerim! Halâl yiyiniz ve sâ"}, {"kisim": 3, "madde": 4, "metin": "Allahü teâlânın emr etdiği bu ticâret ahkâmı, Karl Marks ismli bir yehûdînin serhoş kafası ile ortaya koyduğu, sosyalizm adındaki, siyâsî bir iktisâd rejimi ile taban tabana zıddır. Hür dünyâ devletle"}, {"kisim": 3, "madde": 12, "metin": "cı sahîfesinde diyor ki, (Âyet-i kerîmedeki müdâyene ya’nî borçlanma kelimesi, muâmele ya’nî bey’ ve şirâ demekdir."}, {"kisim": 3, "madde": 15, "metin": "Yine buyurdu ki, (Bir kimse gıdâ maddelerini kırk gün saklarsa, Allahü teâlâ ona darılır. O, Allahü teâlâyı saymamış olur). Bir hadîs-i şerîfde buyuruldu ki, (Bir kimse, hâricden gıdâ maddesi satın al"}, {"kisim": 3, "madde": 16, "metin": "16 — TİCÂRETDE İHSÂN (Kimyâ-i se’âdet) kitâbı, üçüncü asl, dördüncü bâbda buyuruyor ki: Allahü teâlâ, adâlet yapmak emr etdiği gibi, ihsân etmeği de emr ediyor. Bundan evvelki bâbda, adâlet yapmağı bi"}, {"kisim": 3, "madde": 16, "metin": "Çünki, (Alış-verişde kolaylık gösterenlere, Allahü teâlâ merhamet eylesin!) diye düâ buyurmuşdur."}, {"kisim": 3, "madde": 17, "metin": "Münâfıkûn sûresi, dokuzuncu âyet-i kerîmesinde meâlen, (Mallarınız ve çocuklarınız, Allahü teâlâyı, hâtırlamanıza mâni’ olmasın!) buyuruldu."}, {"kisim": 3, "madde": 17, "metin": "] Büyüklerimiz, (Ticâretleri, satışları, Allahü teâlâyı unutmalarına sebeb olmaz) âyet-i kerîmesine ma’nâ verirken diyor ki, demirciler vardı."}, {"kisim": 3, "madde": 17, "metin": "Allahü teâlâ da, şâhid olun, onları afv etdim buyurur)."}, {"kisim": 3, "madde": 24, "metin": "(Buhârî)deki hadîs-i şerîfde, (Ekber-i kebâir, birşeyi Allahü teâlâya ortak etmek, adam öldürmek, anaya, babaya karşı gelmek, yalancı şâhidlik yapmakdır) buyuruldu."}, {"kisim": 3, "madde": 29, "metin": "Bunu yapmak, Allahü teâlâ için çok kolaydır. Ey Rabbimiz! Günâhlarımızı ve işlerimizde yapdığımız isrâfı, taşkınlığı afv et. Bizi doğru yolda bulundur! Kâfirlere gâlib gelmemiz için yardım et! Bu keli"}, {"kisim": 3, "madde": 31, "metin": "cu MEKTÛB Bu mektûb, seyyid Abdülbâkî Sârenkpûrîye yazılmış olup, Eshâb-ı yemîn ve Eshâb-ı şimâli ve Sâbıkları bildirmekdedir: Allahü teâlâya hamd olsun. Onun seçdiği kullara selâm olsun. Allahü teâlâ"}, {"kisim": 3, "madde": 33, "metin": "Nitekim, Hûd sûresinde, yedinci âyet-i kerîmede meâlen, (Allahü teâlâ, gökleri ve yeri altı günde yaratdı ve Arşı, su üzerinde idi) buyuruldu."}, {"kisim": 3, "madde": 33, "metin": "Bu âyet-i kerîme, suyun, yerden ve göklerden önce yaratıldığını gösteriyor."}, {"kisim": 3, "madde": 33, "metin": "cı MEKTÛB Bu mektûb, mevlânâ Hüseyne yazılmış olup, Arşı ve Kürsîyi bildirmekdedir: Allahü teâlâya hamd olsun. Onun beğendiği, seçdiği kullarına selâm olsun! Arş-ı Mecîd, Allahü teâlânın şaşılacak mah"}, {"kisim": 3, "madde": 36, "metin": "Allahü teâlâya kavuşduran yolların iki olduğunu bildirmekdedir: Bismillâhirrahmânirrahîm. Allahü teâlâya hamd olsun ve Onun seçdiği, sevdiği kullarına selâm olsun! İnsanı Allahü teâlâya kavuşduran yol"}, {"kisim": 3, "madde": 37, "metin": "A’râf sûresi ellidördüncü [54] âyetinde meâlen, (Rabbinizi, yalvararak ve gizli ve sessiz çağırınız) ve Ra’d sûresi, otuzuncu [30] âyetinde meâlen, (Biliniz ki, kalbler, yalnız Allahü teâlâyı zikr etm"}, {"kisim": 3, "madde": 37, "metin": "Bunlar gibi, başka âyet-i kerîmeler ve hadîs-i şerîfler de vardır."}, {"kisim": 3, "madde": 37, "metin": "Bütün insanların se’âdet-i ebediyyeye, ya’nî dünyâ ve âhıret iyiliklerine kavuşması, hakîkî sâhibimiz olan Allahü teâlânın ismini çok zikr etmekle hâsıl olur. Şu kadar var ki, zikri, bir Velîden veyâh"}, {"kisim": 3, "madde": 37, "metin": "Zümer sûresinde, meâli, (Kalbleri Allahü teâlâyı zikr etmiyenlere azâb vardır) olan yirminci âyetinde bildirilen azâb bunlar içindir. 2— Yalnız kalb ile yapılan zikrdir. Dil söylemez. İşte bizim yolum"}, {"kisim": 3, "madde": 38, "metin": "(Mâ-sivâ), Allahü teâlâdan başka herşey demekdir. Mâ-sivâ, iki kısmdır: (Âfâk), insanın dışında olan mahlûklardır. (Enfüs), insanda bulunan şeylerdir. Âfâkı unutmak, âfâkı tanıtan ilm-i husûlînin yok "}, {"kisim": 3, "madde": 42, "metin": "Meselâ, imâm-ı hümâm Ca’fer-i Sâdık “radıyallahü anh” buyurmuş ki, (Her âyet-i kerîmeyi sâhibinden [söyleyicisinden] işitdim)."}, {"kisim": 3, "madde": 42, "metin": "ci MEKTÛB Bu mektûb, yine Muhammed Hâşim-i Keşmîye “kuddise sirruh” yazılmış olup, tesavvuf büyüklerinin Allahü teâlâ ile konuşmalarını bildirmekdedir: Bismillâhirrahmânirrahîm. Allahü teâlâya hamd ol"}, {"kisim": 3, "madde": 43, "metin": "ci MEKTÛB Bu mektûb, gizli bilgilerin hazînesi oğulları Muhammed Sa’îd ve Muhammed Ma’sûma “rahmetullahi aleyhimâ” yazılmış olup, Allahü teâlânın mahlûklara yakın olmasını açıklamakda, ademin ve iblîs"}, {"kisim": 3, "madde": 45, "metin": "(Şükr ederseniz, ni’metimi artdırırım) meâlindeki âyet-i kerîmeyi hiç unutmayınız! Önceden, tevhîd bilgileri hâsıl olmağa başladı diyorsunuz."}, {"kisim": 3, "madde": 48, "metin": "cü MEKTÛB Bu mektûb, hâcı Muhammed Firketîye yazılmış olup, hiçbir maddenin Allahü teâlâya ayna olamıyacağını bildirmekdedir: Allahü teâlâya hamd olsun ve seçdiği, beğendiği kullarına selâm olsun! Bu "}, {"kisim": 3, "madde": 49, "metin": "Bu tek varlık Allahü teâlânın kendisidir. Kâinât, bu tek varlığın zuhûrudur, görünüşüdür derler. Bu kâinâta (Zâhir-i vücûd) dediler. Allahü teâlânın ilminde bulunan çeşidli sûretler, bu tek varlığa ak"}, {"kisim": 3, "madde": 50, "metin": "Meâl-i şerîfi (Allahü teâlâ, îmân edenlerin velîsidir) olan âyet meşhûrdur."}, {"kisim": 3, "madde": 50, "metin": "İslâmiyyetin bir sûreti, bir de hakîkati olduğu ve tesavvuf yolunun başında da, sonunda da islâmiyyete uymak lâzım olduğu bildirilmekdedir: Allahü teâlâya hamd olsun! Onun seçdiği, sevdiği kullarına s"}, {"kisim": 3, "madde": 50, "metin": "Cenneti ve Cennetde olan kullarını Allahü teâlâ sever. Onlardan râzıdır. Allahü teâlâ, sonsuz ihsân sâhibi olduğu için, yalnız kalbin tasdîk etmesini, inanmasını îmân olarak kabûl buyurmuşdur."}, {"kisim": 3, "madde": 51, "metin": "(Şûra) sûresindeki âyet-i kerîmede meâlen, (Allahü teâlâ, dilediğini kendine seçer, kendine kavuşmak isteyenlere de, kavuşduran yolu gösterir) buyruldu."}, {"kisim": 3, "madde": 51, "metin": "Mektûbâtın üçüncü cildinin seksenyedinci mektûbundaki ince bilgilerden birkaçını açıklamakdadır: Allahü teâlâya hamd olsun ve Onun seçdiği kullarına selâm olsun! Şefkat ve merhamet ederek bu fakîre [y"}, {"kisim": 3, "madde": 52, "metin": "cu MEKTÛB Bu mektûbu, babasının üstâdı Muhammed Bâkî-billahın “kuddise sirruh” oğlu hâce Muhammed Ubeydüllahın mektûbuna cevâb olarak yazmış olup, vücûd-i ilâhînin, Zât ile aynı olup olmadığı ve fen t"}, {"kisim": 3, "madde": 55, "metin": "Mü’mini râhatlandıran, ancak Allahü teâlâya kavuşmakdır. Her mü’mine mevt, hayâtından dahâ iyidir. Kâfirlere de mevt fâidelidir. Çabuk tükenen şeyin peşinde koşuyorsunuz. Sonsuz kalacak şeye bakmıyor,"}, {"kisim": 3, "madde": 60, "metin": "(Câmi’u-kerâmât-il-evliyâ)dan alınan aşağıdaki yazıları, anlayışlı ve insâflı olan, okuyunca, yapıcı ile yıkıcıyı kolayca ayırabilir: Fahr-üd-dîn-i Râzî, tefsîrinde, Sûre-i Kehfde diyor ki, Ebû Bekr-i"}, {"kisim": 3, "madde": 60, "metin": "Allahü teâlâ, şehîdlerin rûhlarını Cennete koyar. Her gece rûhları bedenleri ile buluşur. Sabâh olunca, yine Cennetde olurlar) buyurdu."}, {"kisim": 3, "madde": 62, "metin": "Allahü teâlâ, yaşıyanların düâları sebebi ile, ölülere dağlar gibi çok rahmet verir. Dirilerin de ölülere hediyyesi, onlar için düâ ve istigfâr etmekdir.) [(Düâ), istemek demekdir. Aç bir adamın, işti"}, {"kisim": 3, "madde": 62, "metin": "Mazher-i Cân-ı Cânân “kaddesallahü teâlâ sirrehül’azîz” hazretleri, fâhişe bir kadının kabri yanına oturmuşdu. Kabre teveccüh eyledi. [Ya’nî hâtırına başka hiçbirşey getirmeyip; yalnız onu düşündü.] B"}, {"kisim": 3, "madde": 64, "metin": "Allahü teâlânın Kur’ân-ı kerîmde, en açık ve en geniş bildirdiği şey, meyyitden kalan mîrâsın nasıl dağıtılacağıdır. Burada yapılacak işlerin çoğu farz olarak emr olunduğu için, hepsine (Ferâiz ilmi) "}, {"kisim": 3, "madde": 66, "metin": "cı MEKTÛB Bu mektûb, Bedî’uddîn-i Sehârenpûrîye yazılmış olup, kabr hayâtını ve tâ’ûn sevâbını bildirmekdedir: Allahü teâlâya hamd olsun. Onun seçdiği iyi insanlara selâm olsun! Kıymetli mektûbunuz ge"}, {"kisim": 3, "madde": 67, "metin": "ci MEKTÛB Bu mektûb, Mirzâ Hüsâmeddîn Ahmede gönderilmiş olup, bu dünyâ sıkıntıları, acı görünse de, insanı yükseltirler ve tâ’ûndan ölmenin kıymetini bildirmekdedir: Önce, Allahü teâlâya hamd ve Peyg"}, {"kisim": 3, "madde": 67, "metin": "Hepimiz, Allahü teâlânın mülküyüz. Hepimiz, Onun huzûruna gideceğiz! Başımıza gelenler, görünüşde çok yakıcı, çok acıdır. Fekat, hakîkatde ilerletici, yükseltici ilâclardır. [İlâclar, elbette acı olur"}, {"kisim": 3, "madde": 69, "metin": "Birkaç gün sonra, Allahü teâlânın lutfü ile, üzüntü ve sıkıntılar gitdi, hiç kalmadı. Onların yerine sevinc, genişlik geldi ki, bizimle uğraşanlar, Allahü teâlânın istediğini istemekde ve yapmakdadırl"}, {"kisim": 3, "madde": 69, "metin": "Ya’nî, Allahü teâlâyı tanıyan kimse, belâdan kurtulmak için birşeye başvurmaz demekdir. Bu sözün ne demek olduğunu iyi anlamalıdır. Çünki, derd ve belâların, sevgiliden geldiğini, Onun dileği olduğunu"}], "hadisler": [{"kisim": 1, "madde": 2, "metin": "Her bilgiyi delîl ile isbât etmek, ya’nî Kur’ân-ı kerîmdeki veyâ hadîs-i şerîflerdeki yerlerini göstermek, âlimlerin vazîfesidir."}, {"kisim": 1, "madde": 4, "metin": "Peygamberimiz Muhammed aleyhisselâmın yolunu bildiren, Kur’ân-ı kerîmden murâd-ı ilâhîyi anlayan, hadîs-i şerîflerden murâd-ı peygamberîyi çıkaran bu büyük âlimlerdir."}, {"kisim": 1, "madde": 5, "metin": "7 — Bu büyük imâmın ve yüzlerce talebesinin ve bunların da yetişdirdiği binlerce büyük insanın yazdığı milyonlarca kitâb, Peygamberimizin yolunu, bütün dünyâya doğru olarak yaymış, tanıtdırmışdır. Şim"}, {"kisim": 1, "madde": 8, "metin": "8 — Her bid’at sâhibi, Kur’ân-ı kerîmde ve hadîs-i şerîflerde ma’nâları açık olmayan i’tikâd bilgilerinde, yanlış te’vîl yaparak, yanlış ma’nâ çıkardığı için, hak yoldan ayrılmışdır."}, {"kisim": 1, "madde": 8, "metin": "9 — Kur’ân-ı kerîmden ve hadîs-i şerîflerden çıkarılan ilmler içinde, kıymetli ve doğru olan, yalnız (Ehl-i sünnet) âlimlerinin anladıkları ve bildirdikleridir."}, {"kisim": 1, "madde": 8, "metin": "Hâlbuki, Peygamberimiz “aleyhisselâm” buyurdu ki, (Kur’ân-ı kerîmden kendi aklı ile, kendi düşüncesi ve bilgisi ile ma’nâ çıkaran kâfirdir)."}, {"kisim": 1, "madde": 9, "metin": "Her mülhid, her bid’at sâhibi ve her câhil, tutduğu yolun, Kur’ân-ı kerîme ve hadîs-i şerîflere uygun olduğunu sanır ve iddi’â eder."}, {"kisim": 1, "madde": 10, "metin": "Böyle olduğu akl ile, Kur’ân-ı kerîm ile ve hadîs-i şerîfler ile ve din büyüklerinin (Basîretleri) ile ya’nî kalb gözleri ile görmeleri ile anlaşılmakdadır."}, {"kisim": 1, "madde": 11, "metin": "[Kâfirler, ya’nî Resûlullahın “sallallahü aleyhi ve sellem” bildirdiği islâm dînini beğenmiyenler, zemâna, asra ve fenne uymuyor diyenler ve mürtedler, müslimânlarla ve müslimânlıkla, açıkça ve alçakç"}, {"kisim": 1, "madde": 11, "metin": "Eshâb-ı kirâm “aleyhimürrıdvân”, birgün Peygamberimize “sallallahü aleyhi ve sellem” sordu ve: (Yemene gidenlerimiz, orada hurma ağaçlarını, başka dürlü aşıladıklarını ve dahâ iyi hurma aldıklarını gö"}, {"kisim": 1, "madde": 16, "metin": "16 — Muhammed Resûlullah “sallallahü aleyhi ve sellem”, mahbûb-i Rabbil’âlemîndir. Ya’nî Allahü teâlânın sevgilisidir. Her şeyin en iyisi, sevgiliye verilir. [Seyyid Abdülhakîm efendi buyurdu ki: (Her"}, {"kisim": 1, "madde": 18, "metin": "(Mürşid-ün-nisâ)daki hadîs-i şerîfde, (Zevcesinin ve çocuklarının haklarını îfâ etmiyenin nemâzları, orucları kabûl olmaz) buyuruldu."}, {"kisim": 1, "madde": 18, "metin": "[Peygamberimiz “sallallahü aleyhi ve sellem” buyuruyor ki, (Hepiniz bir sürünün çobanı gibisiniz."}, {"kisim": 1, "madde": 18, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyuruyor ki, (Birbirinize müslimânlığı öğretiniz."}, {"kisim": 1, "madde": 19, "metin": "19 — (Kimyâ-i se’âdet) kitâbı, beşinci aslında diyor ki: Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Îmânın temeli ve en kuvvetli alâmeti, müslimânları sevmek ve müslimânlara düşmanlık edenl"}, {"kisim": 1, "madde": 21, "metin": "Câmi’ yapmanın, çok sevâb olduğunu bildiren hadîs-i şerîfler vardır."}, {"kisim": 1, "madde": 21, "metin": "Dünyâda yapılan hayrât ve hasenât, ya’nî bütün iyilikler, bütün keşfler, bütün hâller ve bütün ilmler Resûlullahın “sallallahü aleyhi ve sellem” yolunda bulunmak şartı ile, âhıretde işe yarar. Yoksa, "}, {"kisim": 1, "madde": 25, "metin": "Şöyle ki, bir arab şâ’iri, bir sahîfede, edebî san’at inceliklerini göstererek, birşey yazmış, bunun arasına birkaç satır hadîs-i şerîf ve başka yerinde de, aynı şeyi anlatan bir âyet-i kerîme koyup, "}, {"kisim": 1, "madde": 25, "metin": "Okurken, hadîs-i şerîfe gelince, durmuş ve (Burası, yukarısına benzemiyor."}, {"kisim": 1, "madde": 26, "metin": "(Nass), ma’nâları açık ve meydânda olan âyet-i kerîmelere ve hadîs-i şerîflere denir."}, {"kisim": 1, "madde": 26, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” uzak memleketlere gönderdiği Eshâb-ı kirâma, karşılaşacakları mes’elelerde, Kur’ân-ı kerîmin hükmü ile hareket etmelerini, Kur’ân-ı kerîmde bulamazlar ise, "}, {"kisim": 1, "madde": 26, "metin": "Her işinde Peygamberimize “sallallahü aleyhi ve sellem” tâm ma’nâsı ile tâbi’ idi. İctihâd ve istinbâtda, öyle yüksek bir dereceye ulaşmışdı ki, buraya kimse varamadı. [Kendisinden dahâ önceleri, dahâ"}, {"kisim": 1, "madde": 27, "metin": "Ya’nî, Kur’ân-ı kerîmde ve hadîs-i şerîflerde sarîh ve açık bildirilmemiş bulunan ahkâmı ve mes’eleleri, açık ve geniş anlatılmış mes’elelere benzeterek, meydâna çıkarmağa uğraşmakdır."}, {"kisim": 1, "madde": 27, "metin": "O hâlde, ma’nâları açıkça anlaşılmayan âyet-i kerîme ve hadîs-i şerîflerin derinliklerinde bulunan ahkâm-ı islâmiyyeyi ve mesâil-i dîniyyeyi, mefhûm ile ve delâlet ile anlıyabilen büyüklere, ya’nî mut"}, {"kisim": 1, "madde": 30, "metin": "Bu râsih ilmli âlimler, Kur’ân-ı kerîmin ve hadîs-i şerîflerin derin ma’nâlarını ve işâretlerini anlar."}, {"kisim": 1, "madde": 31, "metin": "Bu büyük ni’metin şükrünü yerine getirmelisiniz ve (El mer’ü me’a men ehabbe), ya’nî, (Herkes, âhıretde, dünyâda iken sevmiş olduğu kimselerle berâber bulunacakdır) hadîs-i şerîfinden ümmîdli olmalısı"}, {"kisim": 1, "madde": 32, "metin": "Bu ümmetin yetmişüç fırkaya ayrılacağını bildiren hadîs-i şerîfi açıklamakdadır: Hadîs-i şerîfde bu ümmetin yetmişüç fırkaya ayrılacağı, bunlardan yetmişiki fırkanın Cehenneme gidecekleri bildirildi."}, {"kisim": 1, "madde": 32, "metin": "Bu hadîs-i şerîf, yetmişiki fırkanın Cehennem ateşinde azâb göreceklerini bildiriyor."}, {"kisim": 1, "madde": 34, "metin": "[Sünnet kelimesinin dînimizde üç ma’nâsı vardır: (Kitâb ve sünnet) birlikde söylenince, kitâb, Kur’ân-ı kerîm, sünnet de, hadîs-i şerîfler demekdir."}, {"kisim": 1, "madde": 35, "metin": "Müşrikler aynî necs olsalardı, evvelden beri böyle olmaları gerekirdi ve Resûlullah “sallallahü aleyhi ve sellem” önceden de buna uygun olarak onlara muâmele ederdi. O olmayınca, bu nasıl olsun. Bunda"}, {"kisim": 1, "madde": 35, "metin": "Kâfirlerin dışları, bedenleri nasıl pis olur ki, Peygamberimiz “sallallahü aleyhi ve sellem”, bir yehûdî evinde yemek yidi. Bir müşrikin kabı ile tahâretlendi. Ömer “radıyallahü anh” da, hıristiyan ka"}, {"kisim": 1, "madde": 36, "metin": "Hadîs-i kudsîde buyuruyor ki, (Önce gelenleriniz, sonra gelenleriniz; küçüğünüz, büyüğünüz; dirileriniz, ölüleriniz; insanlarınız, cinleriniz; en müttekî, itâ’atli kulum gibi olsanız, büyüklüğüm artma"}, {"kisim": 1, "madde": 37, "metin": "İş budur, bundan başka herşey hiçdir!\n [(Ma’rifetnâme)de yazılı hadîs-i şerîflerde buyuruyor ki, (Mes’ûd o kimsedir ki, dünyâ onu terk etmezden önce, o dünyâyı terk etmişdir), (Arzûsu âhıret olup, âhı"}, {"kisim": 1, "madde": 38, "metin": "Allahü teâlâ, sizi bütün ayb ve kusûrlardan muhâfaza buyursun! Soruyorsunuz ki, şeyh Muhyiddîn-i Arabî “kuddise sirruh”, (Fütûhât-ı mekkiyye) kitâbında, bir hadîs-i şerîf bildiriyor."}, {"kisim": 1, "madde": 38, "metin": "Bu hadîs-i şerîfde, Peygamberimiz “sallallahü aleyhi ve sellem”, (Allahü teâlâ, yüzbin Âdem yaratmışdır) buyurmakdadır."}, {"kisim": 1, "madde": 41, "metin": "Evliyânın büyükleri, sôfiyyenin imâmları, emr-i ma’rûfu ve nehy-i münkeri terk edici olsalardı, kitâblarında bunları yazarlar mı ve bu derece mübâlega ederler mi idi? Abdülkâdir-i Geylânî hazretleri b"}, {"kisim": 1, "madde": 41, "metin": "Resûlullah “sallallahü aleyhi ve sellem”, bir hadîs-i şerîfde, (Îmânında veyâ ibâdetinde bid’at, bozukluk bulunan bir kimseye, Allah için sert bakanın kalbini, Allahü teâlâ îmânla doldurur ve korkudan"}, {"kisim": 1, "madde": 41, "metin": "Nitekim, bunlardan İmâm-ı Muhammed Behâeddîn-i Buhârî “kuddise sirruh” (Bizim yolumuz urve-i vüskâya yapışmak, ya’nî Resûlullahın “sallallahü aleyhi ve sellem” yolunda ve Onun Eshâbının izinde gitmekd"}, {"kisim": 1, "madde": 41, "metin": "Hâlbuki, (Emr-i ma’rûf) ve (Nehy-i münker) ve (Buğd-ı fillâh) ve (Cihâd-ı fî sebîlillâh), Peygamberimizin “sallallahü aleyhi ve sellem” sünnetinden, belki islâmiyyetin vâciblerinden ve farzlarındandır"}, {"kisim": 1, "madde": 42, "metin": "Bir hadîs-i şerîfde, (Hiçbir şey vera’ gibi olamaz) buyurdu."}, {"kisim": 1, "madde": 42, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Dîninizin direği, temeli vera’dır)."}, {"kisim": 1, "madde": 43, "metin": "[(Tergîb-üs-salât)da diyor ki, Hadîs-i şerîfde buyuruldu ki, (Bir nemâzı özrsüz, vaktinden sonra kılan, seksen hukbe Cehennemde yanacakdır."}, {"kisim": 1, "madde": 43, "metin": "Ondan işitdim ki, Resûlullah “sallallahü aleyhi ve sellem” (Günâh işliyen biri, pişmân olur, abdest alıp nemâz kılar ve günâhı için istigfâr ederse, Allahü teâlâ, o günâhı elbette afv eder. Çünki, All"}, {"kisim": 1, "madde": 48, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Ey Eshâbım! Siz öyle bir zemânda geldiniz ki, Allahü teâlânın emrlerinden onda dokuzunu yapıp, birini yapmazsanız, helâk olursunuz, Cehenneme g"}, {"kisim": 1, "madde": 50, "metin": "(İnsanın dîni, arkadaşının dîni gibidir) hadîs-i şerîfini unutmayınız! Şunu, iyi biliniz ki, âhıreti [se’âdet-i ebediyyeyi] istiyenlerin dünyâ lezzetlerine düşkün olmaması lâzımdır."}, {"kisim": 1, "madde": 50, "metin": "Bu yolun büyüklerinden birini buluncaya kadar, Kur’ân-ı kerîm okuyarak, ibâdetleri yaparak ve kıymetli kitâblarda ve hadîs-i şerîflerde bildirilen düâları, tesbîhleri okuyarak vaktlerinizi ma’mûr edin"}, {"kisim": 1, "madde": 54, "metin": "(Gunyet-üt-tâlibîn) kitâbının bildirdiği hadîs-i şerîfde, Resûlullah “sallallahü aleyhi ve sellem” buyuruyor ki: (Gusl abdesti almağa kalkan bir kimseye, üzerindeki kıl adedince [ya’nî pek çok demekdi"}, {"kisim": 1, "madde": 54, "metin": "(Ey Oğul İlmihâli)nin doksanbirinci sahîfesinde yazılı hadîs-i şerîfde, (Kirlenince, çabuk gusl abdesti alın! Çünki kirâmen kâtibîn melekleri, cünüb gezen kimseden incinir) buyuruldu."}, {"kisim": 1, "madde": 58, "metin": "[(Mecma’ul-enhür)ün ikinci cildinde diyor ki, Peygamberimiz “sallallahü aleyhi ve sellem”, (Yabancı kadınların yüzlerine şehvet ile bakanların gözlerine, kıyâmet günü ergimiş kızgın kurşun dökülecekdi"}, {"kisim": 1, "madde": 60, "metin": "60 — NEMÂZ VAKTLERİ (Mukaddimet-üs-salât), (Tefsîr-i Mazherî) ve (Halebî-yi kebîr)deki hadîs-i şerîfde buyuruldu ki: (Cebrâîl aleyhisselâm Kâ’be kapısı yanında iki gün bana imâm oldu."}, {"kisim": 1, "madde": 60, "metin": "Nemâz sayısının beş olduğu, bu hadîs-i şerîfden de anlaşılmakdadır."}, {"kisim": 1, "madde": 61, "metin": "] (Mevâhib-i ledünniyye)de diyor ki, (Hicretin birinci senesinde, Resûlullah “sallallahü aleyhi ve sellem”, Eshâb-ı kirâma sordu. Kimisi, nemâz vaktlerini bildirmek için, nasârâ gibi nâkûs, ya’nî çan "}, {"kisim": 1, "madde": 61, "metin": "] (Tebyîn-ül-hakâık)da ve (Tahtâvî)de diyor ki, (Resûlullah “sallallahü aleyhi ve sellem”, Bilâl-i Habeşîye, (İki parmağını kulaklarına koy! Böylece, sesin çok çıkar) buyurdu."}, {"kisim": 1, "madde": 63, "metin": "Farz olduğu, Kur’ân-ı kerîmde ve hadîs-i şerîflerde, açıkça bildirilmişdir."}, {"kisim": 1, "madde": 63, "metin": "Farz nemâzların ehemmiyyetini bildirmek için, Muhammed Rebhâmî “rahmetullahi aleyh”, dörtyüzkırkdört kitâbdan toplıyarak, hicretin sekizyüzotuzbeşinci [835] senesinde Hindistânda yazdığı (Riyâd-ün-nâs"}, {"kisim": 1, "madde": 63, "metin": "Müfessirlerin şâhı, Abdüllah ibni Abbâs “radıyallahü anhümâ” diyor ki, Resûlullahdan “sallallahü aleyhi ve sellem” işitdim. Buyurdu ki, (Nemâz kılmıyanlar, kıyâmet günü, Allahü teâlâyı kızgın olarak b"}, {"kisim": 1, "madde": 63, "metin": "Peygamberimiz “sallallahü teâlâ aleyhi ve sellem” el ile üçden fazla vurmağı bile, yasak etmişdi.] Çocuklara, başka ibâdetleri de öğretmek ve yapmağa alışdırmak, günâhlardan men’ etmek lâzımdır. Farz "}, {"kisim": 1, "madde": 64, "metin": "Resûlullahın ve Eshâb-ı kirâmın ve Tâbi’înin ve hattâ dört imâmın ağız ile niyyet etdikleri işitilmemişdir. [1. ci kısm, elliikinci maddenin 2. ci sahîfesine bakınız!] İmâm-ı Rabbânî “rahmetullahi ale"}, {"kisim": 1, "madde": 67, "metin": "3 — Kur’ân-ı kerîmde ve hadîs-i şerîfde bulunmıyan düâları okumak, bozar."}, {"kisim": 1, "madde": 68, "metin": "Nemâzda abes hareket ve kabristânda sesle gülmek, hadîs-i şerîf ile men’ edilmişdir."}, {"kisim": 1, "madde": 68, "metin": "Hadîs-i şerîfde, (Yehûdîlere benzememek için nemâzları, na’lın ile kılınız) buyuruldu."}, {"kisim": 1, "madde": 69, "metin": "Bu halîfelere ve Eshâb-ı kirâmın icmâ’ına uymamız, hadîs-i şerîf ile emr olunmuşdur)."}, {"kisim": 1, "madde": 70, "metin": "Hadîs-i şerîfde, (Müttekî bir âlim ile nemâz kılan, bir Peygamber ile kılmış gibidir) buyuruldu."}, {"kisim": 1, "madde": 70, "metin": "Ebüssü’ûd efendi fetvâsında buyuruyor ki, (Sâlih ve fâcir arkasında nemâz kılınız!) hadîs-i şerîfi, câmi’ imâmları için değil, Cum’a kıldıran emîrler, vâlîler içindir."}, {"kisim": 1, "madde": 73, "metin": "Bu mes’elede siz ne buyurursunuz? Cevâb 2 — Efendim! Şehâdet parmağı ile işâret etmenin câiz olduğunu bildiren hadîs-i şerîfler çokdur."}, {"kisim": 1, "madde": 73, "metin": "Ravda-i mubâreke nasıl olur da, dahâ üstün olur? [Medîne câmi’i içinde, Resûlullahın “sallallahü aleyhi ve sellem” kabr-i şerîfi ile câmi’in o zemânki minberi arasındaki, yirmialtı metre uzunluğundaki"}, {"kisim": 1, "madde": 73, "metin": "İmâm-ı Muhammed Şeybânî, (Peygamberimiz “sallallahü aleyhi ve sellem” mubârek parmağı ile, işâret ederdi. Biz de, Onun gibi, parmağımızı kaldırır ve indiririz. İmâm-ı a’zam Ebû Hanîfe de böyle söyledi"}, {"kisim": 1, "madde": 74, "metin": "İbni Teymiyye ve İbni Hazm, hükmü şübheli olan âyet-i kerîmeleri ve hadîs-i şerîfleri te’vîl etdiler."}, {"kisim": 1, "madde": 74, "metin": "Hadîs-i şerîfde, (Bir nemâzı uykuda geçiren veyâ unutan kimse, sonraki nemâzı cemâ’at ile kılarken hâtırlarsa, imâmla nemâzı bitirip, sonra önceki nemâzını kazâ etsin! Bundan sonra, imâmla kıldığını t"}, {"kisim": 1, "madde": 77, "metin": "İyi dinleyiniz! Peygamberimiz “sallallahü aleyhi ve sellem”, (En büyük hırsız, kendi nemâzından çalan kimsedir) buyurdu."}, {"kisim": 1, "madde": 77, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem”, bir kimseyi nemâz kılarken, rükü’unu ve secdelerini temâm yapmadığını görüp, (Sen nemâzlarını böyle kıldığın için, Muhammedin “aleyhissalâtü vesselâm” dîni"}, {"kisim": 1, "madde": 79, "metin": "(Sahîh-i Buhârî)deki bir hadîs-i şerîfde buyuruldu ki: (Bir kimse, Ramezân ayında oruc tutmağı farz bilir, vazîfe bilir ve orucun sevâbını, Allahü teâlâdan beklerse, geçmiş günâhları afv olur)."}, {"kisim": 1, "madde": 79, "metin": "Hâfız [ya’nî hadîs âlimi] Abdül’ azîm-i Münzirî, (Ettergîb vetterhîb) kitâbında ve hâfız Ahmed Beyhekî (Sünen) kitâbında, Câbir bin Abdüllahdan “radıyallahü teâlâ anh” haber verdikleri bir hadîs-i şer"}, {"kisim": 1, "madde": 79, "metin": "(Riyâd-ün-nâsıhîn) kitâbında diyor ki: (Buhârî) kitâbında, Ebû Hüreyre “radıyallahü anh” diyor ki: Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki: (Ramezân ayı gelince, Cennet kapıları açılır."}, {"kisim": 1, "madde": 79, "metin": "İmâm-ül-eimme, Muhammed bin İshak bin Huzeyme yazıyor ki, Selmân-ı Fârisî “radıyallahü anh” bildirdi ki, Resûlullah “sallallahü aleyhi ve sellem” Şa’bân ayının son günü hutbede buyurdu ki: (Ey Müslimâ"}, {"kisim": 1, "madde": 81, "metin": "Bir hadîs-i şerîfde, (Hasîslerin en kötüsü, [kesmesi vâcib olduğu hâlde] kurban kesmiyendir) buyuruldu."}, {"kisim": 1, "madde": 82, "metin": "Tahtâvî “rahmetullahi teâlâ aleyh” (İmdâd) hâşiyesi, oruc sonunda diyor ki, (Nezr yapmanın câiz olduğu âyet-i kerîmeden ve hadîs-i şerîfden anlaşılmakdadır."}, {"kisim": 1, "madde": 82, "metin": ")] Nezri yerine getirmek lâzım olduğu, Kur’ân-ı kerîmde ve hadîs-i şerîfde bildirilmiş ve icmâ-i ümmet hâsıl olmuşdur."}, {"kisim": 1, "madde": 84, "metin": "(Künûz-üd-dekâık)da yazılı Bezzârın bildirdiği hadîs-i şerîfde, (Kadın, yanında bir mahremi olmadan hacca gidemez!) buyuruldu."}, {"kisim": 1, "madde": 85, "metin": "Resûlullah “sallallahü aleyhi ve sellem” üzümü yirken Besmele okudu. Addâs “radıyallahü teâlâ anh”, o zemân hıristiyan idi. Bunu işitince şaşırdı. (Yıllarca buralardayım. Kimseden böyle söz duymadım. "}, {"kisim": 1, "madde": 85, "metin": "Resûlullah: Yûnüs aleyhisselâmın memleketinden imişsin, buyurdu."}, {"kisim": 1, "madde": 90, "metin": "5— Hadîs-i şerîf okuyana selâm verilmez."}, {"kisim": 1, "madde": 90, "metin": ") (Rıyâd-us-sâlihîn) kitâbında, selâmı cem’ kelimesi şeklinde söylemek lâzım olduğunu bildiren hadîs-i şerîf yazılıdır."}, {"kisim": 1, "madde": 92, "metin": "92 — ÎSÂ “aleyhisselâm” İNSAN İDİ, ONA TAPILMAZ Resûlullah “sallallahü aleyhi ve sellem” efendimize, Necrândan bir hıristiyan hey’eti gelmişdi. Necrân, Hicâz ile Yemen arasında bir şehr idi. Bunlar, a"}, {"kisim": 1, "madde": 92, "metin": "Resûlullah “sallallahü aleyhi ve sellem”, bunları dîne da’vet etdi. Birkaç âyet-i kerîme okudu. Îmâna gelmediler. (Biz senden önce îmân etdik) dediler. Resûlullah “sallallahü aleyhi ve sellem”, (Yalan"}, {"kisim": 1, "madde": 94, "metin": "Bir hadîs-i şerîfde, Rabbinden şöyle nakl etdi: (Yedi kat göklerin ve bunlarda bulunanların ve yedi kat yerin hepsi, Lâ ilâhe illallah kelimesi ile ölçülse, bu kelimenin sevâbı dahâ çok olur) buyuruld"}, {"kisim": 1, "madde": 94, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem”, (Zikrin en kıymetlisi, Lâ ilâhe illallah demekdir) buyurdu."}, {"kisim": 1, "madde": 96, "metin": "Çok kimselerin islâm dînine girmesine, Resûlullahın güzel ahlâkı sebeb oldu). Muhammed aleyhisselâmın bin mu’cizesi göründü, dost düşman herkes de bunu söyledi. Bu kadar mu’cizelerin en kıymetlisi, ed"}, {"kisim": 1, "madde": 96, "metin": ") (Mesâbîh) kitâbında, Enes bin Mâlik “radıyallahü anh” buyuruyor ki, (Resûlullaha “sallallahü aleyhi ve sellem” on sene hizmetcilik etdim. Bana bir kerre üf demedi. Şunu niçin böyle yapdın, bunu niçi"}, {"kisim": 1, "madde": 97, "metin": "Bunu isbât eden âyet-i kerîme ve hadîs-i şerîflerden ba’zıları şunlardır: 1 — Kur’ân-ı kerîmden sonra en kıymetli, en doğru kitâb olan (Buhârî-yi şerîf)deki bir hadîs-i şerîfde, Peygamberimiz buyurdu "}, {"kisim": 1, "madde": 97, "metin": "2 — Binlerle hadîs kitâblarından ikinciliği kazanmış olan, imâm-ı Müslimin “rahmetullahi teâlâ aleyh” kitâbındaki hadîs-i şerîfde, (Allahü teâlâ, İsmâ’îl “aleyhisselâm” evlâdından, Kinâne ismindeki ki"}, {"kisim": 1, "madde": 97, "metin": "Resûlullah “sallallahü aleyhi ve sellem” efendimiz, bütün dedelerinin temiz olduğunu bildirdiğine göre, kâfir olan, pis olan Âzerin, bu nûra kavuşmaması, bunun için de İbrâhîm aleyhisselâmın babası ol"}, {"kisim": 1, "madde": 97, "metin": "Peygamberimizin “sallallahü teâlâ aleyhi ve sellem” ve bütün Peygamberlerin “aleyhimüsselâm” babalarının ve analarının hiçbiri kâfir değil, aşağı kimseler değildi. Bunu isbât eden âyet-i kerîme ve had"}, {"kisim": 1, "madde": 98, "metin": "2 — Sa’îd bin Mensûrun ve ibni Ebî Şeybenin ve hâfız [hadîs âlimi] Ebû Ya’lânın “rahmetullahi aleyhim ecma’în” bildirdikleri bir hadîs-i şerîfde, Ebû Sa’îd-i Hudrî “radıyallahü anh” diyor ki, (Resûlul"}, {"kisim": 1, "madde": 98, "metin": ") Bu çeşidli hadîs-i şerîfler gösteriyor ki, Resûlullah “sallallahü aleyhi ve sellem” bu âyet-i kerîmeyi okurken ve ümmetine tavsıye buyururken, Kur’ân-ı kerîmdeki şeklini değişdirmemiş, hep (Sübhâne "}, {"kisim": 1, "madde": 98, "metin": "4 — Yine imâm-ı Taberânî “rahmetullahi teâlâ aleyh” diyor ki, Abdüllah ibni Zeyd bin Erkam, babasından işiterek diyor ki, (Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Bir kimse nemâz sonunda"}, {"kisim": 2, "madde": 1, "metin": "Hepsi, Kur’ân-ı kerîme ve hadîs-i şerîflere uygundur."}, {"kisim": 2, "madde": 1, "metin": "Sahîh olan hadîs-i şerîflerde, Peygamberimiz “sallallahü aleyhi ve sellem” buyuruyor ki, (Unutulmuş bir sünnetimi meydâna çıkarana yüz şehîd sevâbı vardır!)."}, {"kisim": 2, "madde": 1, "metin": "Resûlullaha biri geldi. Onu uzakdan görünce, (Kabîlesinin en kötüsüdür) buyurdu."}, {"kisim": 2, "madde": 2, "metin": "Bunun içindir ki, Resûlullah “sallallahü aleyhi ve sellem”, gazâlarında ve sıkıntılı zemânlarında, muhâcirlerin fakîrleri hürmetine Allahü teâlâdan yardım dilerdi. Askeri, ordusu olduğu hâlde, muhâcir"}, {"kisim": 2, "madde": 3, "metin": "Hadîs-i şerîfde buyuruldu ki, (Üç dürlü baba vardır: Dünyâya getiren baba, kızını veren baba ve ilm öğreten baba."}, {"kisim": 2, "madde": 3, "metin": "Resûlullaha uymağa ve dînini öğrendiği üstâdını sevmeğe teşvîk etmekdedir: Bismillâhirrahmânirrahîm. Kardeşim seyyid mîr Muhibbullahın şerefli mektûbu geldi. Sıkıntılardan dolayı ümmîdsiz olduğunu bil"}, {"kisim": 2, "madde": 4, "metin": "İşte, birkaç sene Mısrda, Bağdâdda bulunup da argo lisânı arabca öğrenenlerin ve eline bir ceb lügati alıp da, Kur’ân-ı kerîmi ve hadîs-i şerîfleri tercemeye kalkışan yeni din âlimlerinin(!), para kaz"}, {"kisim": 2, "madde": 5, "metin": "5 — TEFSÎR KİTÂBLARI, HADÎS-İ ŞERÎFLER Bu mektûb, râsih ilmli, hakîkî din âlimi, seyyid Abdülhakîm Efendinin “rahmetullahi aleyh” bir mektûba cevâbı olup, tefsîri ve hadîs-i şerîfleri bildirmekde, din"}, {"kisim": 2, "madde": 5, "metin": "Kelâm ilminin, âyet-i kerîmelerden ve hadîs-i şerîflerden nasıl çıkarıldığını öğreten ilmdir."}, {"kisim": 2, "madde": 5, "metin": "İslâm dîninin emr etdiği bu bilgileri, Resûlullah “sallallahü aleyhi ve sellem” ikiye ayırmış, (El-ilmü ilmân, ilmü ebdân ve ilmü edyân) buyurmuşdur."}, {"kisim": 2, "madde": 5, "metin": "Resûlullahın “sallallahü aleyhi ve sellem” ef’âl, akvâl ve ahvâlini öğretir. 6 — (Üsûl-i fıkh) ilmi. Fıkh bilgilerinin âyet-i kerîmelerden ve hadîs-i şerîflerden nasıl çıkarıldığını öğretir. (Menâr) a"}, {"kisim": 2, "madde": 6, "metin": "6 — HADÎS-İ ŞERÎFLERİN ÇEŞİDLERİ [1308] senesinde İstanbulda basılan, (Mahzen-ül’ulûm) kitâbının, birinci cüz’, yüzotuzaltıncı sahîfesinde ve (Eşi’at-ül-leme’ât)in üçüncü sahîfesinde hadîs-i şerîfleri"}, {"kisim": 2, "madde": 6, "metin": "2 — (Hadîs-i müsned): Resûl-i ekreme “sallallahü aleyhi ve sellem” isnâd eden Sahâbînin “radıyallahü teâlâ anhüm ecma’în” ismi bildirilen hadîs-i şerîflerdir."}, {"kisim": 2, "madde": 6, "metin": "5 — (Hadîs-i mevsûl): Sahâbînin “radıyallahü teâlâ anhüm ecma’în”, (Resûlullahdan işitdim, böyle buyurdu) diyerek haber verdiği, hadîs-i müsned-i müttasıl demekdir."}, {"kisim": 2, "madde": 6, "metin": "12 — (Hadîs-i kudsî): Ma’nâsı, Allahü teâlâ tarafından, kelimeleri ise, Resûl-i ekrem “sallallahü aleyhi ve sellem” tarafından olan hadîs-i şerîflerdir."}, {"kisim": 2, "madde": 6, "metin": "Hadîs-i kudsîleri söylerken, Peygamber efendimizi “sallallahü aleyhi ve sellem” bir nûr kaplardı ve hâlinden belli olurdu."}, {"kisim": 2, "madde": 7, "metin": "Allahü teâlâ, (Hadîs-i kudsî)de buyuruyor ki, (Kazâ ve kaderime râzı olmıyan, beğenmiyen ve gönderdiğim belâlara sabr etmiyen, benden başka Rab arasın."}, {"kisim": 2, "madde": 11, "metin": "[(Tefsîr-i Mazherî)de, Enbiyâ sûresinin seksenyedinci âyetinin tefsîrinde, hadîs-i şerîfde buyuruldu ki, (Birinize derd ve belâ gelince, Yûnüs Peygamberin düâsını okusun! Allahü teâlâ Onu muhakkak kur"}, {"kisim": 2, "madde": 11, "metin": "(Tergîb-üs-salât), ellidördüncü faslındaki hadîs-i şerîfde, (Sabâh, kalkınca, üç kerre Bismillâhillezî lâ-yedurru ma’ asmihî şey’ün fil-erdı velâ fissemâi ve hüvessemî’ul’alîm okuyana akşama kadar, hi"}, {"kisim": 2, "madde": 13, "metin": "[Uzun bir hadîs-i şerîfde] (Her mü’minin kalbinde, Allahü teâlânın bir vâ’ızı vardır) buyuruldu."}, {"kisim": 2, "madde": 14, "metin": "Bir hadîs-i şerîfde, (Kur’ân-ı kerîm okuyan çok kimse vardır ki, Kur’ân-ı kerîm bunlara la’net eder) buyuruldu."}, {"kisim": 2, "madde": 14, "metin": "Başka bir hadîs-i şerîfde, (Oruc tutan çok kimse vardır ki, onların orucu, yalnız açlık ve susuzluk çekmek olur) buyuruldu."}, {"kisim": 2, "madde": 14, "metin": "Yetmişdokuzuncu sahîfede diyor ki, Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Müslimân demek, müslimânlara eli ile, dili ile zarar vermiyen kimse demekdir)."}, {"kisim": 2, "madde": 16, "metin": "Fıkh bilgileri, Kur’ân-ı kerîmden, hadîs-i şerîflerden, icmâ’-ı ümmetden ve kıyâsdan meydâna gelmekdedir."}, {"kisim": 2, "madde": 16, "metin": "Kur’ân-ı kerîmden veyâ hadîs-i şerîflerden veyâ icmâ’-ı ümmetden çıkarılan ahkâm-ı islâmiyyeye (Kıyâs-ı fükahâ) denir."}, {"kisim": 2, "madde": 18, "metin": "Kur’ân-ı kerîmin ma’nâsını anlıyabilmek için, ilm-i lügat, ilm-i metn-i lügat, ilm-i bedî’, ilm-i beyân, ilm-i me’ânî, ilm-i belâgat, ilm-i üsûl-i tefsîr gibi çeşidli ilmleri iyi öğrenmek, sarf, nahv,"}, {"kisim": 2, "madde": 18, "metin": "Yukarıda sayılı ilmlerde mütehassıs olan, islâm dünyâsında asrlardan beri parmakla gösterilen büyük tefsîr âlimleri, (Âlimler, Peygamberlerin vârisleridir) hadîs-i şerîfi ile medh olunan islâm dîninin"}, {"kisim": 2, "madde": 18, "metin": "18 — ŞEFÂ’AT, ÖLÜLERE YARDIM Süâl: Zümer sûresinin, otuzuncu âyetiyle sarâhaten, Peygamberimizin “sallallahü aleyhi ve sellem” öldüğü belli iken, hâlâ kabr ziyâreti ile ölülerden şefâ’at istemek olur "}, {"kisim": 2, "madde": 19, "metin": "Hadîs-i şerîfde, (Allahü teâlânın, bir kulunu sevmemesinin alâmeti, onun mâ-lâ-ya’nî ile vakt geçirmesidir) buyuruldu."}, {"kisim": 2, "madde": 19, "metin": "Kur’ân-ı kerîmde ve hadîs-i şerîflerde, bu işe ehemmiyyet verilmediği için, halîfeler üzerinde durmanın, üsûl-i dinden olmayıp, fudûl-i dinden olduğu anlaşılmakdadır."}, {"kisim": 2, "madde": 23, "metin": "Kur’ân-ı kerîm ile ve hadîs-i şerîfler ile red edilmekdedir."}, {"kisim": 2, "madde": 23, "metin": "Hâlbuki, Resûlullahın “sallallahü aleyhi ve sellem” her sözü vahy ile idi. Nitekim Vennecmi sûresi, üçüncü âyetinde meâlen, (O, boşuna konuşmaz. Hep, vahy olunanı söylemekdedir) buyuruldu."}, {"kisim": 2, "madde": 23, "metin": "Doğru yolda yürümeni nasîb eylesin! Böyle şübheleri ortaya atarak, üç halîfeyi ve başka Sahâbîleri lekelemek istiyenler, insâf etseler ve insanların en iyisinin sohbetinin şerefini, kıymetini anlasala"}, {"kisim": 2, "madde": 23, "metin": "cı MEKTÛB Bu mektûb, hâce Ebül-Hasen Behâdır Bedahşîye yazılmış olup, Peygamberimizin “sallallahü aleyhi ve sellem” vefât edeceğine yakın kâğıd istediğini açıklamakdadır: Allahü teâlâya hamd olsun. On"}, {"kisim": 2, "madde": 23, "metin": "Bu sözlerden herbiri ayrı birer cevâb gibidir: Birinci önsöz — Peygamberimizin “sallallahü aleyhi ve sellem” her sözü, vahy ile değil idi. Vennecmi sûresindeki, (O, boş söz söylemez!) meâlindeki âyet-"}, {"kisim": 2, "madde": 24, "metin": "Bir başka hadîs-i şerîfde, (Şeytâna söğmeyiniz! Şerrinden, Allahü teâlâya sığınınız) buyuruldu."}, {"kisim": 2, "madde": 24, "metin": "Düşmanlara la’net etmek emr edilmeyince, dostlara la’net sevâb olur mu? Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Bir kimse, şeytâna la’net ederse, ben zâten mel’ûn oldum."}, {"kisim": 2, "madde": 25, "metin": "Bunun için Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki: (Ümmetimden herhangi biri, Uhud dağı kadar altın sadaka verse, Eshâbımın bir müd arpa sadakasına verilen sevâba kavuşamaz)."}, {"kisim": 2, "madde": 29, "metin": "(Eş-şer’u tahtesseyf) hadîs-i şerîfinin haber verdiği gibi, islâm güneşi batarak yeryüzü bugünkü hâlini aldı."}, {"kisim": 2, "madde": 31, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem”, (İlm, Çinde de olsa alınız!) buyurdu."}, {"kisim": 2, "madde": 34, "metin": "Bir hadîs-i şerîfde de, (Nikâh yapmak, benim sünnetimdir."}, {"kisim": 2, "madde": 34, "metin": "Dahâ nice hadîs-i şerîfler, zihnlerdeki yanlış fikrleri kaldırdı."}, {"kisim": 2, "madde": 34, "metin": "O büyükler, Resûlullahın sohbetinde bulunmakla, Ona yakın olmakla, zühdleri, tevekkülleri ve rızâları artdığı için, evlendikleri zemân, nefsleri islâmiyyetin beğenmediği sebeblere bağlanmaz, harâm kaz"}, {"kisim": 2, "madde": 39, "metin": "(Tenbîh-ul-gâfilîn)de yazılı hadîs-i şerîfde, (Dört şeyi yapan, ya’nî kocasına hıyânet etmiyen, beş vakt nemâz kılan, Ramezân-ı şerîfde oruc tutan ve [onsekiz erkekden] başkasına, [başı, saçı, kolları"}, {"kisim": 2, "madde": 39, "metin": "(Tenbîh-ul-gâfilîn)de ve (Şir’a) şerhinde yazılı hadîs-i şerîfde, Peygamberimiz “sallallahü teâlâ aleyhi ve sellem”, (Bir kadın, beş vakt nemâzını kılar, Ramezân ayında oruc tutar, nâmûsunu korur ve z"}, {"kisim": 2, "madde": 40, "metin": "Bir hadîs-i şerîfde, (Çok kimse vardır ki, yidikleri ve giydikleri harâmdır."}, {"kisim": 2, "madde": 40, "metin": "Halâl kazanmanın ehemmiyyetini gösteren dahâ nice hadîs-i şerîfler ve büyüklerin sözleri vardır."}, {"kisim": 2, "madde": 40, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Halâl kazanmak her müslimâna farzdır)."}, {"kisim": 2, "madde": 40, "metin": "Resûlullah “sallallahü aleyhi ve sellem” bunun için, (Halâl kazanmak her müslimâna farzdır) buyurdu."}, {"kisim": 2, "madde": 41, "metin": "Libya hükûmeti Evkaf idâresinin çıkardığı (El-Hedyül-islâmî) adındaki Mecellenin 1393 Hicrî ve 1973 Mîlâdî senesi ikinci sayısında, Libya Müftîsi şeyh Tâhir-üz-Zâvî, fetvâsında diyor ki, (Hadîs-i şerî"}, {"kisim": 2, "madde": 41, "metin": "Başka bir hadîs-i şerîfde, (Ey Allahın kulları! Hasta olunca, tedâvî etdiriniz! Çünki Allahü teâlâ, hastalık gönderince, ilâcını da gönderir) buyuruldu."}, {"kisim": 2, "madde": 42, "metin": "Çünki hadîs-i şerîfde, (Şerâb, üzüm ve hurmadan olur) buyuruldu."}, {"kisim": 2, "madde": 43, "metin": "Hanefî mezhebine gelince; büyük âlim İbni Nüceym-i Mısrî “rahmetullahi teâlâ aleyh”, (Eşbâh) kitâbında buyuruyor ki, (Âyet-i kerîmede ve hadîs-i şerîflerde harâm olduğu bildirilmiyen şeyler, aslı üzer"}, {"kisim": 2, "madde": 43, "metin": "Şerâb habîslerin en kötüsü olduğu hâlde ve Resûlullah “sallallahü aleyhi ve sellem” islâmiyyetin bildiricisi olduğu hâlde, şerâba harâm diyemedi. Âyet-i kerîme ile yasak edilmesini bekledi. O hâlde, t"}, {"kisim": 2, "madde": 44, "metin": "İmâm-ı Tirmizînin “rahmetullahi teâlâ aleyh”, Ebî Berzeden “radıyallahü anh” getirerek yazdığı hadîs-i şerîfde, Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Kıyâmet günü herkes, dört süâle"}, {"kisim": 2, "madde": 44, "metin": "Doğru oldukları herkesce bilinen iki temel hadîs kitâbında, [(Buhârî) ve (Müslim)de] Peygamberimiz “sallallahü aleyhi ve sellem”, (Malı boş yere saçmayınız!) buyuruyor."}, {"kisim": 2, "madde": 45, "metin": "Hadîs-i şerîfde, (İyiliklerin başı açlıkdır."}, {"kisim": 2, "madde": 45, "metin": "Hadîs-i şerîfde, (Sağ el ile yiyiniz."}, {"kisim": 2, "madde": 45, "metin": "[Resûlullahın “sallallahü aleyhi ve sellem” yimekden sonra okuduğu ve okunmasını emr etdiği düâlar, (Şir’at-ül-islâm) şerhinde ve (Mevâhib-i ledünniyye)de yazılıdır.] Yimekden evvel el yıkarken, önce "}, {"kisim": 2, "madde": 45, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem”, (Ben kulum. Kullar gibi, yere oturup yirim) buyurdu."}, {"kisim": 2, "madde": 46, "metin": "Perhîzi, hadîs-i şerîflerden ve tecribeli kimselerden ve tabîbden öğrenmelidir."}, {"kisim": 2, "madde": 46, "metin": "Resûlullah “sallallahü aleyhi ve sellem”, hazret-i Alî ile bir eve gitdi. Meyve getirdiler. Hazret-i Alînin gözleri ağrıyordu. Meyveden kendisi yidi. Hazret-i Alîye, (Sen yime! Göz ağrısına zarar veri"}, {"kisim": 2, "madde": 46, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” (Allahü teâlâ, her hastalığın ilâcını yaratmışdır. Yalnız, ölüme çâre yokdur) ve (Hastalıkların başı, çok yimekdir. İlâcların başı, perhîzdir) ve (Hastaları"}, {"kisim": 2, "madde": 47, "metin": "Bir hadîs-i şerîfde, (Allahü teâlâya tam tevekkül etseydiniz, kuşların rızkını verdiği gibi, size de gönderirdi."}, {"kisim": 2, "madde": 47, "metin": "Bir hadîs-i şerîfde, (Bir kimse, Allahü teâlâya sığınırsa, Allahü teâlâ, onun her işine yetişir."}, {"kisim": 2, "madde": 47, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyuruyor ki, (Ümmetimden bir kısmını, bana gösterdiler."}, {"kisim": 2, "madde": 47, "metin": "Çünki, Resûlullah “sallallahü aleyhi ve sellem”, (Efsûn yapan ve ateş ile dağlıyan kimse, Allahü teâlâya tevekkül etmemiş olur) buyurdu."}, {"kisim": 2, "madde": 48, "metin": "Hadîs-i şerîfde buyuruldu ki, (Kader, tedbîr ile, sakınmakla değişmez."}, {"kisim": 2, "madde": 48, "metin": "Bir hadîs-i şerîfde, (Kazâ-i mu’allakı, hiçbirşey değişdiremez."}, {"kisim": 2, "madde": 48, "metin": "Bunun için, Resûlullah “sallallahü aleyhi ve sellem” her zemân, (Allahümme, yâ mukallibelkulûb, sebbit kalbî, alâ dînik) düâsını okurdu [ki, Ey büyük Allahım! Kalbleri iyiden kötüye, kötüden iyiye çev"}, {"kisim": 2, "madde": 48, "metin": "Çünki, hadîs-i kudsîde: (İnsanların kalbi Rahmânın kudretindedir."}, {"kisim": 2, "madde": 50, "metin": "Âdem “aleyhisselâm” da, (O hâlde ben, Allahü teâlânın, kitâbında yazdığını yapdım) diyerek, hak kazandığını bildiren hadîs-i şerîf de, sözümün doğru olduğunu gösteriyor dese, bu kimseyi günâh işlemesi"}, {"kisim": 2, "madde": 50, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Bir kimse, bütün ömrünce Cehennem ateşine götürecek günâhlar yapar."}, {"kisim": 2, "madde": 52, "metin": "Müziğin Cennetde de bulunduğunu ve orada nasıl olduğunu, dünyâda erkeklere de, kadınlara da harâm olan kısmlarını bildiren hadîs-i şerîflerden birkaçı, (Kurret-ül’uyûn) kitâbının son bâbında yazılıdır"}, {"kisim": 2, "madde": 52, "metin": "Fâsıklar [kötü kimseler] ve Ehl-i kitâb gibi tegannî yaparak hazîn okumak ve bunu dinlemek hadîs-i şerîf ile men’ olundu."}, {"kisim": 2, "madde": 54, "metin": "Şâziliyye yolunun reîsi, Ebül-Hasen Alî Şâzilînin “kuddise sirruh” (Her ân ve zemân, Peygamberimizin “sallallahü aleyhi ve sellem” mubârek yüzü, gözümün önündedir) buyurduğu, (Mîzân-ı kübrâ)da yazılıd"}, {"kisim": 2, "madde": 54, "metin": "[Evliyânın rûhları çağrılınca, işiteceklerini ve çağrılan yerde hâzır olacaklarını, Allahü teâlâ, birinci kısmın kırkaltıncı maddesi sonunda yazılı hadîs-i kudsîde açıkca bildirmekdedir."}, {"kisim": 2, "madde": 57, "metin": "Allahü teâlâ, Peygamberlerin efendisi hurmetine “aleyhi ve aleyhim ve alâ Âl-i küllin minessalevâti efdalühâ ve minetteslîmâti ekmelühâ”, sizi, size lâyık olmıyan herşeyden korusun! Sizin, Resûlullahı"}, {"kisim": 2, "madde": 58, "metin": "ci MEKTÛB Bu mektûb, hâce Şerefeddîn-i Hüseyne yazılmış olup, Resûlullaha uygun her işin, zikr olduğu bildirilmekdedir: Elhamdülillahi ve selâmün alâ ibâdihillezînestafâ. Azîz oğlumun, mevlânâ Abdürre"}, {"kisim": 2, "madde": 63, "metin": "[Bu hadîs-i şerîfin sahîh olduğu, kitâbımızın ikinci kısmının, beşinci maddesinde de yazılıdır."}, {"kisim": 2, "madde": 68, "metin": "Peygamberlere vâris oldukları hadîs-i şerîfde bildirilen âlimlere ulemâ-i râsihîn denir “rahmetullahi teâlâ aleyhim ecma’în”."}, {"kisim": 2, "madde": 71, "metin": "Hadîs-i şerîfde bildirilen (İhsân) mertebesinden bir ışık’ın kalbde parlamasına, (Ayn-ül-yakîn) denir."}, {"kisim": 2, "madde": 73, "metin": "Bu uzun mektûbun son kısmının fârisîden tercemesi, aşağıdadır: Kur’ân-ı kerîmde ve hadîs-i şerîflerde öyle bilgiler vardır ki, bunlar te’vîl edilmeden anlaşılamaz."}, {"kisim": 2, "madde": 73, "metin": "Hadîs-i şerîfde, (Küfrü açık bilinmiyen kimseye kâfir diyen, kâfir olur) buyuruldu."}, {"kisim": 2, "madde": 73, "metin": "[Bir kelimenin, Allahü teâlâ ve Resûlullah tarafından, açık bildirilmemiş ma’nâlarından, islâmiyyete uygun olanı seçmeğe (Te’vîl) denir. Bunu herkes yapamaz.] Evliyânın sözlerini de te’vîl etmek, meâl"}, {"kisim": 2, "madde": 73, "metin": "Buna cevâb olarak deriz ki: Her müslimânın, farzlarda, vâciblerde ve müekked sünnetlerde, Resûlullaha tâbi’ olması lâzımdır. Âciz olmak, mücâhede ve gazâ yapamamak için özrdür. Hem de, geceleri, mubâr"}, {"kisim": 3, "madde": 1, "metin": "Abdülvehhâb-ı Şa’rânî “rahmetullahi aleyh”, (Tezkire-i Kurtubî) muhtasarında diyor ki: İbni Mâcenin bildirdiği hadîs-i şerîfde, (Bir zemân gelecek."}, {"kisim": 3, "madde": 1, "metin": "Hadîs-i şerîfde, (Bid’at işliyenlere büyük diyen, müslimânlığı yıkmağa yardım etmiş olur) buyurulmuşdur."}, {"kisim": 3, "madde": 1, "metin": "[Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki: (Bir zemân gelecek ki, ümmetimde müslimânlığın yalnız adı kalacak."}, {"kisim": 3, "madde": 1, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” (Bid’atlerin hepsi dalâletdir, yoldan çıkmakdır) buyurdu."}, {"kisim": 3, "madde": 2, "metin": "ci MEKTÛB Bu mektûb, bir sâliha hanıma “rahmetullahi teâlâ aleyhâ” yazılmış olup, kadınlara lâzım olan nasîhatleri bildirmekdedir: Kadınların, Resûlullaha “sallallahü aleyhi ve sellem” söz verdiklerin"}, {"kisim": 3, "madde": 2, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” erkeklerle sözleşdikden sonra, kadınlarla sözleşmeğe başladı. Kadınlarla yalnız söz ile olup, mubârek eli, kadınların ellerine dokunmadı. Kötü huylar, kadın"}, {"kisim": 3, "madde": 2, "metin": "Hâlbuki hadîs-i kudsîde buyuruldu ki, (Oruc benim için tutulur."}, {"kisim": 3, "madde": 3, "metin": "Ebû Hüreyre “radıyallahü anh” buyuruyor ki, Resûlullahdan “sallallahü aleyhi ve sellem” işitdim. Buyurdu ki, (Allahü teâlâ güzeldir."}, {"kisim": 3, "madde": 6, "metin": "Çünki kendiliğinden yetişen otu, yerden çıkan suyu kullanmak ve birinin ateşinde ısınmak, herkesin hakkı olduğu hadîs-i şerîfde bildirildi."}, {"kisim": 3, "madde": 15, "metin": "Bir hadîs-i şerîfde buyuruldu ki, (Bir kimse, hâricden gıdâ maddesi satın alıp, şehre getirir ve piyasaya göre satarsa, sadaka vermiş gibi sevâb kazanır veyâ köle âzâd etmiş gibi sevâb kazanır)."}, {"kisim": 3, "madde": 15, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Bir kimse gıdâ maddelerini alıp, pahâlı olup da satmak için kırk gün saklarsa, hepsini fakîrlere parasız dağıtsa, günâhını ödiyemez)."}, {"kisim": 3, "madde": 16, "metin": "] Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki, (Alış-verişde kolaylık gösterenlere, Allahü teâlâ, her işinde kolaylık gösterir)."}, {"kisim": 3, "madde": 17, "metin": "Hadîs-i şerîfde buyuruldu ki, (En iyi ticâret, bezzâzlıkdır, kumaş satmakdır."}, {"kisim": 3, "madde": 17, "metin": "Bir hadîs-i şerîfde buyuruldu ki, (Melekler insanların amel defterlerini götürdükleri zemân, başında ve sonunda iyi iş yazılı ise, gün ortasında yapılanları ona bağışlarlar)."}, {"kisim": 3, "madde": 23, "metin": "Hadîs-i şerîfde, (Günâh işliyeni gören, eli ile mâni’ olsun."}, {"kisim": 3, "madde": 23, "metin": "Hadîs-i şerîflere, kendine göre ma’nâ vererek, vâcib olmıyan şeyi yapmağa kalkışmamalıdır."}, {"kisim": 3, "madde": 24, "metin": "(Berîka)da, (hıkd) kötü huyu anlatılırken yazılı hadîs-i şerîfde, (Kul haklarını ödeyen, her nemâzdan sonra onbir ihlâs-i şerîf okuyan ve kâtilini afv ederek ölen Cennete girecekdir) buyuruldu."}, {"kisim": 3, "madde": 24, "metin": "(Buhârî)deki hadîs-i şerîfde, (Ekber-i kebâir, birşeyi Allahü teâlâya ortak etmek, adam öldürmek, anaya, babaya karşı gelmek, yalancı şâhidlik yapmakdır) buyuruldu."}, {"kisim": 3, "madde": 29, "metin": "Bizi doğru yolda bulundur! Kâfirlere gâlib gelmemiz için yardım et! Bu kelimenin üstünlüklerini dinleyiniz: Resûlullah “sallallahü teâlâ aleyhi ve âlihi ve selleme ve bâreke” buyurdu ki: (Lâ ilâhe ill"}, {"kisim": 3, "madde": 31, "metin": "Evet bir hadîs-i şerîfde, (Zemânların en hayrlısı benim zemânımdır) buyurmuşdur."}, {"kisim": 3, "madde": 31, "metin": "Peygamberimiz “aleyhi ve alâ âlihissalâtü vesselâm”, belki de bunun için (Önce gelenleri mi dahâ hayrlıdır? Yoksa sonra gelenleri mi? Belli değil) buyurdu."}, {"kisim": 3, "madde": 33, "metin": "[Kelimeleri Peygamberimizden “sallallahü aleyhi ve sellem”, ma’nâları, Allahü teâlâdan olan hadîs-i şerîflere, (Hadîs-i kudsî) denir."}, {"kisim": 3, "madde": 33, "metin": "Allahü teâlâ, hadîs-i kudsîde, (Yere ve göke sığmam."}, {"kisim": 3, "madde": 34, "metin": "(İnsan, sevdiği ile berâber olur) hadîs-i şerîfi bunu bildirmekdedir."}, {"kisim": 3, "madde": 36, "metin": "Resûlullahdan “aleyhi ve alâ âlihissalâtü vesselâm” gelen feyzler, ma’rifetler hep onun vâsıtası ile gelir. Fâtımatüz-Zehrâ ve hazret-i Hasen ve hazret-i Hüseyn “radıyallahü teâlâ anhüm”, bu makâmda, "}, {"kisim": 3, "madde": 37, "metin": "A’râf sûresi ellidördüncü [54] âyetinde meâlen, (Rabbinizi, yalvararak ve gizli ve sessiz çağırınız) ve Ra’d sûresi, otuzuncu [30] âyetinde meâlen, (Biliniz ki, kalbler, yalnız Allahü teâlâyı zikr etm"}, {"kisim": 3, "madde": 37, "metin": "Büyüklerin yolda bulunanlara öğretdikleri râbıta, Tevbe sûresinin yüzyirminci âyetinin, (Hep sâdıklarla birlikde bulunun!) ve En’âm sûresinin elliikinci âyetinin, (Rablerini istiyenlerle berâber olmağ"}, {"kisim": 3, "madde": 38, "metin": "Bir hadîs-i şerîfde, (Câhiliyye zemânında iyi olanlarınız, müslimân olup din bilgilerini öğrenince de, en iyiniz olur!) buyuruldu."}, {"kisim": 3, "madde": 40, "metin": "Câhilliklerini ve yalan inanışlarını, Kur’ân-ı kerîmden ve hadîs-i şerîflerden üstün tutmuşlardır."}, {"kisim": 3, "madde": 50, "metin": "[(Künûz-üd-dekâık)deki hadîs-i şerîflerde buyuruluyor ki, (Âlimler, Peygamberlerin vârisleridir), (Evliyâ ol kimselerdir ki, Onlar görülünce, Allah hâtırlanır), (Herşeyin hâsıl olduğu yer vardır."}, {"kisim": 3, "madde": 55, "metin": "Hadîs-i şerîfde buyuruldu ki, (İnsanlar uykudadır, ölünce uyanırlar)."}, {"kisim": 3, "madde": 55, "metin": "Peygamberimiz “sallallahü aleyhi ve sellem” buyurdu ki, (Lezzetleri yıkan, eğlencelere son veren ölümü çok hâtırlayınız!)."}, {"kisim": 3, "madde": 58, "metin": "Hadîs-i şerîfde buyuruldu ki: (Cenâzeyi kırk adım taşıyanın kırk büyük günâhı afv olur."}, {"kisim": 3, "madde": 58, "metin": "(Künûz-üd-dekâık)da yazılı ibni Mâcenin bildirdiği hadîs-i şerîfde, (Cenâzeyi yüksek sesle ve ateş, ışık ve başka şeyler taşıyarak götürmeyiniz!) buyuruldu."}, {"kisim": 3, "madde": 59, "metin": "Hadîs-i şerîfde, (Ana-babasının veyâ ikisinden birinin kabrini her Cum’a günleri ziyâret edenin günâhları afv olur."}, {"kisim": 3, "madde": 59, "metin": "Hadîs-i şerîfde buyuruldu ki, (Bir mü’minin kabrini ziyâret ederken, Allahümme innî es’elüke-bi-hurmet-i Muhammed aleyhisselâm en lâ tü’azzibe hâzelmeyyit derse, o meyyitin azâbı kıyâmete kadar ref’ o"}, {"kisim": 3, "madde": 59, "metin": "Resûlullah “sallallahü aleyhi ve sellem”, kabr ziyâret eden kadınlara la’net etdi. Sonradan izn verdi diyenler vardır. Ba’zıları da mekrûhdur dedi. Kadınların cenâze götürmeleri sözbirliği ile câiz de"}, {"kisim": 3, "madde": 59, "metin": ") Resûlullah “sallallahü aleyhi ve sellem”, mü’min olan akrabâsının ve Eshâbının kabrlerini ziyâret ederdi. Hadîs-i şerîfde buyuruldu ki, (Bir mü’minin kabrini ziyâret ederken, Allahümme innî es’elüke"}, {"kisim": 3, "madde": 60, "metin": "Kabre korken, (Muhammedün resûlullah ve Ebû Bekr-i Sıddîk ve Ömer-i şehîd ve Osmân-ı rahîm) sesini duyduk. Ebû Nu’aym ve İbni Asâkir bildiriyorlar ki, (Bir sapık, hazret-i Hasenin kabri üzerine pisled"}, {"kisim": 3, "madde": 60, "metin": "Beyhekî, Ya’lâ bin Mürreden haber veriyor: Ya’lâ, Resûlullah ile bir kabr yanına geldi. Kabrde azâb olduğunu işitip, Resûlullaha haber verdi. Resûlullah, (Ben de işitdim. Söz taşıdığı ve üzerine idrâr"}, {"kisim": 3, "madde": 62, "metin": "(Makâmât-ı Mazheriyye)de diyor ki: (Hadîs-i şerîfde, (Bir kimse, kendisi için veyâ başkası için yetmişbin aded Kelime-i tevhîd okursa, günâhları afv olur) buyuruldu."}, {"kisim": 3, "madde": 62, "metin": "Resûlullah “sallallahü aleyhi ve sellem” buyurdu ki: (Ölünün mezârdaki hâli, imdâd diye bağıran, denize düşmüş kimseye benzer."}, {"kisim": 3, "madde": 63, "metin": "Hadîs-i şerîfde, (Bir kimse, başkası yerine oruc tutamaz ve nemâz kılamaz."}, {"kisim": 3, "madde": 63, "metin": "Bu hadîs-i şerîfler, (Berîka)nın 94."}, {"kisim": 3, "madde": 64, "metin": "(Tezkire-i Kurtubî) muhtasarında, İbni Mâce ve Dâre Kutnînin “rahmetullahi teâlâ aleyhim ecma’în “bildirdikleri hadîs-i şerîfde, (Ferâiz ilmini öğrenmeğe çalışınız! Bu ilmi gençlere öğretiniz! Ferâiz "}, {"kisim": 3, "madde": 67, "metin": "İnsanların en iyisi, en kıymetlisi olan Eshâb-ı kirâma “aleyhimürrıdvân” böyle yapılınca, bizler gibi günâhı çok olanlar, hesâba dâhil olur mu? Hadîs-i şerîfde buyuruldu ki, (Tâ’ûn, eski ümmetlere, az"}, {"kisim": 3, "madde": 67, "metin": "ci MEKTÛB Bu mektûb, Mirzâ Hüsâmeddîn Ahmede gönderilmiş olup, bu dünyâ sıkıntıları, acı görünse de, insanı yükseltirler ve tâ’ûndan ölmenin kıymetini bildirmekdedir: Önce, Allahü teâlâya hamd ve Peyg"}, {"kisim": 3, "madde": 69, "metin": "(Allahü teâlânın yaratdıklarında, gönderdiklerinde hayr, iyilik vardır) hadîs-i şerîfi meşhûrdur."}, {"kisim": 3, "madde": 69, "metin": "[(Miftâh-un-necât) da yazılı hadîs-i şerîfde, (Bir kimse, mü’minler için, hergün yirmibeş kerre, istigfâr okursa, Allahü teâlâ, bu kimsenin kalbinden gıl ve hasedi çıkarır."}]};
